var e={},t=JSON.parse(`{"e100":{"name":"Curcumin","note":"Natürlicher Kurkuma-Farbstoff.","detail":{"risks":"Das gelbe Pigment der Kurkuma-Wurzel, das seit Jahrtausenden beim Kochen verwendet wird. Es wird vom Körper nur schlecht aufgenommen und weitgehend unverändert wieder ausgeschieden.","benefits":"","interestingFact":"","research":""}},"e101":{"name":"Riboflavin","note":"Als Farbstoff verwendetes Vitamin B2.","detail":{"risks":"Ein Vitamin mit Doppelnutzen als gelber Farbstoff – genau dasselbe Riboflavin, das Ihr Körper nutzt, um Nahrung in Energie umzuwandeln.","benefits":"","interestingFact":"","research":""}},"e102":{"name":"Tartrazin","note":"Azofarbstoff, der mit Hyperaktivität bei Kindern in Verbindung gebracht wird; EU-Warnhinweis erforderlich.","detail":{"risks":"Ein synthetischer Azofarbstoff. Einer der „Southampton Six“-Farbstoffe, die in der Studie im Lancet 2007 mit erhöhter Hyperaktivität bei Kindern in Verbindung gebracht wurden – EU-Produkte, die ihn enthalten, müssen einen Warnhinweis tragen.","benefits":"","interestingFact":"","research":""}},"e104":{"name":"Chinolingelb","note":"Synthetischer Farbstoff, der mit Hyperaktivität in Verbindung gebracht wird; EU-Warnhinweis erforderlich.","detail":{"risks":"Ein synthetisches Gelb, das in der EU nach den Southampton-Ergebnissen eingeschränkt wurde; in den USA, Kanada und Japan für Lebensmittel verboten.","benefits":"","interestingFact":"","research":""}},"e110":{"name":"Gelborange S","note":"Azofarbstoff, der mit Hyperaktivität bei Kindern in Verbindung gebracht wird; EU-Warnhinweis erforderlich.","detail":{"risks":"Ein aus Erdöl gewonnener Azofarbstoff aus den „Southampton Six“. Die EFSA hat seine zulässige tägliche Dosis im Jahr 2009 drastisch gesenkt, bevor sie sie nach neuen Daten teilweise wieder lockerte.","benefits":"","interestingFact":"","research":""}},"e120":{"name":"Cochenille (Karmin)","note":"Aus Insekten gewonnener Rotton; kann allergische Reaktionen auslösen.","detail":{"risks":"Ein tiefes Rot, das aus getrockneten Cochenilleschildläusen gewonnen wird – etwa 70.000 Insekten stecken in 500 g Farbstoff. Natürlich, aber einer der wenigen Farbstoffe mit dokumentierten (gelegentlich schweren) allergischen Reaktionen.","benefits":"","interestingFact":"","research":""}},"e122":{"name":"Azorubin","note":"Azofarbstoff, der mit Hyperaktivität in Verbindung gebracht wird; EU-Warnhinweis erforderlich.","detail":{"risks":"Ein synthetischer Azofarbstoff, der in den USA und mehreren anderen Ländern verboten ist; EU-Produkte benötigen einen Warnhinweis zu Hyperaktivität.","benefits":"","interestingFact":"","research":""}},"e124":{"name":"Cochenillerot A","note":"Azofarbstoff, der mit Hyperaktivität in Verbindung gebracht wird; EU-Warnhinweis erforderlich.","detail":{"risks":"Ein erdbeerroter Azofarbstoff aus den „Southampton Six“, der in den USA verboten ist. Die EFSA hat die zulässige Aufnahmemenge im Jahr 2009 um das Vierfache gesenkt.","benefits":"","interestingFact":"","research":""}},"e129":{"name":"Allurarot AC","note":"Azofarbstoff, der mit Hyperaktivität in Verbindung gebracht wird; EU-Warnhinweis erforderlich.","detail":{"risks":"Der meistverwendete rote Farbstoff in den USA, dennoch ist in der EU ein Warnhinweis zu Hyperaktivität vorgeschrieben. Neue Mäusestudien diskutieren zudem darmentzündliche Wirkungen bei hohen Dosen.","benefits":"","interestingFact":"","research":""}},"e131":{"name":"Patentblau V","note":"Synthetisches Blau; seltene allergische Reaktionen.","detail":{"risks":"Ein synthetischer Farbstoff, der auch medizinisch zur Markierung von Lymphknoten bei Operationen verwendet wird – wo auch sein seltenes Allergiepotenzial erstmals dokumentiert wurde.","benefits":"","interestingFact":"","research":""}},"e132":{"name":"Indigotin","note":"Synthetisches Blau, im Allgemeinen gut verträglich.","detail":{"risks":"Der synthetische Verwandte von Indigo, dem Farbstoff, der Jeans blau färbt. Schlechtes Aufnahmeverhalten; die EFSA sah bei den gemeldeten Verzehrmengen kein Sicherheitsbedenken.","benefits":"","interestingFact":"","research":""}},"e133":{"name":"Brillantblau FCF","note":"Synthetischer Farbstoff; in Lebensmitteldosen im Allgemeinen gut verträglich.","detail":{"risks":"Ein Triarylmethan-Blau, das oft mit Tartrazin kombiniert wird, um Grüntöne zu erzeugen. Weniger als 5% werden aufgenommen; der Rest wird direkt ausgeschieden.","benefits":"","interestingFact":"","research":""}},"e140":{"name":"Chlorophylle","note":"Natürliches grünes Pflanzenpigment.","detail":{"risks":"Dasselbe Molekül, das Blätter grün macht und die Fotosynthese antreibt, gewonnen aus Gras, Brennnesseln oder Luzerne.","benefits":"","interestingFact":"","research":""}},"e141":{"name":"Kupferkomplexe der Chlorophylle","note":"Stabilisiertes natürliches grünes Pigment.","detail":{"risks":"Chlorophyll, dessen Magnesiumkern durch Kupfer ersetzt wurde, was das Grün beim Erhitzen stabil hält – das Kupfer bleibt gebunden und wird nicht aufgenommen.","benefits":"","interestingFact":"","research":""}},"e142":{"name":"Grün S","note":"Synthetisches Grün, in mehreren Ländern eingeschränkt.","detail":{"risks":"Ein synthetischer Farbstoff, der in der EU zugelassen ist (Minzsauce, Erbsenkonserven), in Kanada, Japan und Norwegen jedoch verboten ist. Schlechtes Aufnahmeverhalten.","benefits":"","interestingFact":"","research":""}},"e150a":{"name":"Einfaches Zuckerkulör","note":"Einfacher Karamellduft/Farbstoff; die unbedenklichste Zuckerkulör-Klasse.","detail":{"risks":"Hergestellt durch Erhitzen von Zucker, ähnlich wie beim Karamellisieren in der Pfanne, nur industriell gesteuert. Die einzige Zuckerkulör-Klasse, die ohne Ammoniak- oder Sulfitchemie hergestellt wird.","benefits":"","interestingFact":"","research":""}},"e150b":{"name":"Sulfitlaugen-Zuckerkulör","note":"Zuckerkulör, hergestellt mit Sulfitverbindungen.","detail":{"risks":"Zuckerkulör, das mit Sulfitverbindungen hergestellt und in Spirituosen wie Whisky und Brandy verwendet wird. Restsulfit ist vernachlässigbar.","benefits":"","interestingFact":"","research":""}},"e150c":{"name":"Ammoniak-Zuckerkulör","note":"Enthält Spuren von 4-MEI, bei hoher Aufnahme umstritten.","detail":{"risks":"Zuckerkulör, das mit Ammoniumverbindungen hergestellt wird; bei dem Verfahren entstehen Spuren von 4-Methylimidazol (4-MEI), das in hochdosierten Mäusestudien Tumore verursachte. Die EFSA stuft die typische Aufnahme als sicher ein, hat jedoch Grenzwerte festgelegt.","benefits":"","interestingFact":"","research":""}},"e150d":{"name":"Ammonsulfit-Zuckerkulör","note":"Cola-Zuckerkulör; enthält Spuren von 4-MEI, bei hoher Aufnahme umstritten.","detail":{"risks":"Mengenmäßig der meistverbrauchte Farbstoff der Welt – er macht Cola braun. Gleiche 4-MEI-Debatte wie bei E150c; Kalifornien verlangt ab bestimmten Werten Krebs-Warnhinweise, die EFSA hält normalen Verzehr für sicher.","benefits":"","interestingFact":"","research":""}},"e153":{"name":"Pflanzenkohle","note":"Schwarzer Farbstoff; von der EU überprüft, Nanopartikel-Debatte.","detail":{"risks":"Im Grunde Aktivkohle in Lebensmittelqualität. Die EFSA stellte fest, dass einige Chargen Nanopartikel enthalten, die klein genug sind, um aufgenommen zu werden, was eine laufende Überprüfung der Reinheit auslöste.","benefits":"","interestingFact":"","research":""}},"e155":{"name":"Braun HT","note":"Azo-Braun, in mehreren Ländern verboten.","detail":{"risks":"Ein synthetisches Azo-Braun, das in Schokoladenkuchen verwendet wird; in den USA, Kanada und Großteilen Skandinaviens verboten, in der EU innerhalb von Grenzwerten zugelassen.","benefits":"","interestingFact":"","research":""}},"e160a":{"name":"Carotine","note":"Natürliches oranges Pigment, Provitamin A.","detail":{"risks":"Das Pigment von Karotten und Kürbissen; Ihr Körper wandelt es nach Bedarf in Vitamin A um und speichert den Überschuss harmlos im Fett (isst man genug davon, färbt sich die Haut buchstäblich orange).","benefits":"","interestingFact":"","research":""}},"e160b":{"name":"Annatto","note":"Natürlicher Samenfarbstoff; seltene Empfindlichkeitsreaktionen.","detail":{"risks":"Ein orange-roter Extrakt aus den Samen des Annattostrauchs, der von den Azteken als Körperfarbe und heute zum Färben von Cheddar und Red Leicester verwendet wird. Seltene Überempfindlichkeitsreaktionen sind dokumentiert.","benefits":"","interestingFact":"","research":""}},"e160c":{"name":"Paprikaextrakt","note":"Natürlicher Farbstoff aus Paprika.","detail":{"risks":"Konzentriertes Pigment aus süßer roter Paprika – dasselbe Capsanthin, das Paprika rot macht, ohne die Schärfe.","benefits":"","interestingFact":"","research":""}},"e160d":{"name":"Lycopin","note":"Natürliches Tomatenpigment.","detail":{"risks":"Das Rot von Tomaten und Wassermelonen; wird auch als eigenständiges Antioxidationsmittel erforscht.","benefits":"","interestingFact":"","research":""}},"e161b":{"name":"Lutein","note":"Natürliches Tagetes-Pigment.","detail":{"risks":"Ein gelbes Carotinoid aus den Blütenblättern der Studentenblume (Tagetes), identisch mit dem Lutein, das in der Netzhaut Ihres Auges angereichert ist.","benefits":"","interestingFact":"","research":""}},"e162":{"name":"Rote-Bete-Rot","note":"Natürliches Rote-Bete-Pigment.","detail":{"risks":"Betanin, gepresst aus Roter Bete. So harmlos, dass sein einziger „Nebeneffekt“ derselbe ist wie der von Roter Bete.","benefits":"","interestingFact":"","research":""}},"e163":{"name":"Anthocyane","note":"Natürliche Beeren-/Traubenpigmente.","detail":{"risks":"Die purpurrote Pigmentfamilie aus Traubenschalen, Beeren und Rotkohl. Sie verändern ihre Farbe je nach Säuregehalt – rot im sauren Milieu, blau im alkalischen –, weshalb derselbe Zusatzstoff in verschiedenen Produkten unterschiedlich aussehen kann.","benefits":"","interestingFact":"","research":""}},"e170":{"name":"Calciumcarbonat","note":"Kalk – mineralisches Weiß, auch eine Calciumquelle.","detail":{"risks":"Einfacher Kalk/Kalkstein, der als weißer Oberflächenfarbstoff und Trennmittel verwendet wird. Es ist dieselbe Verbindung wie in Calcium-Nahrungsergänzungsmitteln.","benefits":"","interestingFact":"","research":""}},"e171":{"name":"Titandioxid","note":"In EU-Lebensmitteln seit 2022 verboten – Genotoxizität konnte nicht ausgeschlossen werden.","detail":{"risks":"Ein strahlend weißes Mineralpigment (auch in Farbe und Sonnencreme). Die EFSA konnte eine DNA-Schädigung durch sich anreichernde Nanopartikel nicht mehr ausschließen, und die EU verbot es 2022 in Lebensmitteln – in den USA ist es weiterhin legal.","benefits":"","interestingFact":"","research":""}},"e172":{"name":"Eisenoxide","note":"Mineralische Pigmente (Rosttöne).","detail":{"risks":"Gereinigtes Eisenoxid – chemisch gesehen kontrollierter Rost –, das gelbe, rote und schwarze Töne verleiht. Praktisch unlöslich und wird nicht aufgenommen.","benefits":"","interestingFact":"","research":""}},"e173":{"name":"Aluminium","note":"Metallischer Oberflächenfarbstoff; Bedenken hinsichtlich der Aluminiumaufnahme.","detail":{"risks":"Metallisches Aluminium für silberne Dekorationen. Trägt zur Gesamtaufnahme von Aluminium über die Nahrung bei, für die die EFSA einen strengen wöchentlichen Grenzwert festlegt, da es sich im Körper anreichert.","benefits":"","interestingFact":"","research":""}},"e174":{"name":"Silber","note":"Dekorativer metallischer Farbstoff.","detail":{"risks":"Echtes Blattsilber, meist auf Süßwaren (die Silberperlen auf Kuchen). In Dekorationsdosen im Darm inert.","benefits":"","interestingFact":"","research":""}},"e175":{"name":"Gold","note":"Dekorativer metallischer Farbstoff.","detail":{"risks":"Echtes Blattgold. Chemisch inert – es wandert komplett durch den Körper, was es zum teuersten Zusatzstoff macht, der genau gar nichts tut.","benefits":"","interestingFact":"","research":""}},"e200":{"name":"Sorbinsäure","note":"Mildes Konservierungsmittel; gelegentliche Hautreaktionen.","detail":{"risks":"Erstmals aus Vogelbeeren isoliert; blockiert das Wachstum von Schimmel und Hefen durch Störung ihrer Enzyme. Ihr Körper verstoffwechselt sie wie eine Fettsäure.","benefits":"","interestingFact":"","research":""}},"e201":{"name":"Natriumsorbat","note":"Salz der Sorbinsäure, mildes Konservierungsmittel.","detail":{"risks":"Die Natriumform der Sorbinsäure (ursprünglich in Vogelbeeren entdeckt). Sie löst sich in wässrigen Lebensmitteln besser und wirkt identisch – sie blockiert Enzyme von Schimmelpilzen und Hefen.","benefits":"","interestingFact":"","research":""}},"e202":{"name":"Kaliumsorbat","note":"Gängiges mildes Konservierungsmittel.","detail":{"risks":"Das Standard-Konservierungsmittel für Käse, Wein und Backwaren – ein gut lösliches Salz der Sorbinsäure (ursprünglich aus Vogelbeeren). Gehört zu den am besten verträglichen Konservierungsstoffen überhaupt.","benefits":"","interestingFact":"","research":""}},"e203":{"name":"Calciumsorbat","note":"Salz der Sorbinsäure, mildes Konservierungsmittel.","detail":{"risks":"Die Calciumform der Sorbinsäure, die eingesetzt wird, wenn ein natriumfreies Konservierungsmittel gewünscht ist. Wird wie eine Fettsäure verstoffwechselt, genau wie der Rest der Sorbat-Familie.","benefits":"","interestingFact":"","research":""}},"e210":{"name":"Benzoesäure","note":"Kann mit Vitamin C Benzol bilden; Allergieauslöser.","detail":{"risks":"Kommt natürlicherweise in Preiselbeeren und Zimt vor; hemmt Hefen und Bakterien in sauren Lebensmitteln. Der Haken: In Kombination mit Vitamin C in Erfrischungsgetränken können sich Spuren von Benzol bilden, einem bekannten Krebserreger – weshalb in den 2000er Jahren Rezepturen angepasst wurden.","benefits":"","interestingFact":"","research":""}},"e211":{"name":"Natriumbenzoat","note":"Kann mit Vitamin C Benzol bilden; in Kombination mit Farbstoffen mit Hyperaktivität in Verbindung gebracht.","detail":{"risks":"Das lösliche Salz der Benzoesäure, Standard in Erfrischungsgetränken. Die Southampton-Studie testete es zusammen mit Azofarbstoffen und fand in dieser Kombination Hinweise auf Hyperaktivität; das Problem der Benzolbildung mit Vitamin C gilt auch hier.","benefits":"","interestingFact":"","research":""}},"e212":{"name":"Kaliumbenzoat","note":"Benzoat-Konservierungsmittel; dieselbe Benzol/Vitamin C-Bedenken.","detail":{"risks":"Die Kaliumform von Natriumbenzoat, bevorzugt für natriumarme Rezepturen. Dieselbe Chemie: wirksam gegen Hefen in sauren Getränken, dieselbe Warnung bezüglich Benzolbildung mit Vitamin C.","benefits":"","interestingFact":"","research":""}},"e213":{"name":"Calciumbenzoat","note":"Benzoat-Konservierungsmittel; dieselbe Benzol/Vitamin C-Bedenken.","detail":{"risks":"Die Calciumform der Benzoat-Familie, wird selten verwendet. Teilt die Eigenschaften der Familie – wirkt nur in sauren Lebensmitteln und trägt die Warnung bezüglich Vitamin C und Benzol.","benefits":"","interestingFact":"","research":""}},"e214":{"name":"Ethylparaben","note":"Paraben-Konservierungsstoff; Debatte über hormonelle Wirkung.","detail":{"risks":"Eines der wenigen Parabene, die in Lebensmitteln noch zugelassen sind (selten verwendet). Parabene ahmen in Laborstudien schwach Östrogen nach, weshalb sie wegen möglicher endokriner Wirkungen unter Beobachtung stehen.","benefits":"","interestingFact":"","research":""}},"e218":{"name":"Methylparaben","note":"Paraben-Konservierungsstoff; Debatte über hormonelle Wirkung.","detail":{"risks":"Ein Paraben-Konservierungsstoff, der eher aus Kosmetika bekannt ist und gelegentlich in Überzügen für Süßwaren eingesetzt wird. Die endokrine Frage – schwache Östrogennachahmung in Laborstudien – betrifft die gesamte Paraben-Familie.","benefits":"","interestingFact":"","research":""}},"e219":{"name":"Natriummethylparaben","note":"Paraben-Konservierungsstoff; Debatte über hormonelle Wirkung.","detail":{"risks":"Das wasserlösliche Natriumsalz von Methylparaben. Gleiche Familie, gleiche endokrine Beobachtung.","benefits":"","interestingFact":"","research":""}},"e220":{"name":"Schwefeldioxid","note":"Sulfit – ein wichtiges Allergen, zerstört Vitamin B1.","detail":{"risks":"Das uralte Wein-Konservierungsmittel – schon die Römer verbrannten Schwefelkerzen in Fässern. Es stoppt Bräunung und Mikroben, ist aber ein echtes Allergen: Etwa 3–10% der Asthmatiker reagieren darauf, weshalb \\"enthält Sulfite\\" eine pflichtmäßige Kennzeichnung ist. Zudem zerstört es Thiamin (Vitamin B1) in Lebensmitteln.","benefits":"","interestingFact":"","research":""}},"e221":{"name":"Natriumsulfit","note":"Sulfit-Allergen.","detail":{"risks":"Ein Sulfitsalz, das dasselbe aktive SO₂ wie E220 freisetzt – gleiche antimikrobielle Wirkung, gleiche Warnung für Asthmatiker, gleiche Kennzeichnungspflicht als Allergen.","benefits":"","interestingFact":"","research":""}},"e222":{"name":"Natriumhydrogensulfit","note":"Sulfit-Allergen.","detail":{"risks":"Ein Vertreter der Sulfit-Familie, der in Wein und eingelegten Lebensmitteln verwendet wird. Alle Sulfite teilen die Allergen-Warnung und die Zerstörung von Vitamin B1 von E220.","benefits":"","interestingFact":"","research":""}},"e223":{"name":"Natriummetabisulfit","note":"Sulfit-Allergen.","detail":{"risks":"Die Pulverform der Schwefeldioxid-Chemie, häufig in Trockenobst und Wein. Gleiche Allergen-Warnung wie E220 – getrocknete Aprikosen bleiben dadurch orange.","benefits":"","interestingFact":"","research":""}},"e224":{"name":"Kaliummetabisulfit","note":"Sulfit-Allergen.","detail":{"risks":"Die \\"Campden-Tablette\\" des Winzers – das Standard-Sulfit für die private und gewerbliche Weinherstellung. Gleiche Allergen- und Vitamin-B1-Warnhinweise wie beim Rest der Familie.","benefits":"","interestingFact":"","research":""}},"e226":{"name":"Calciumsulfit","note":"Sulfit-Allergen.","detail":{"risks":"Ein selten genutztes Calciumsalz der Sulfit-Familie; teilt die Warnung für Asthmatiker und die Kennzeichnungspflicht der Gruppe.","benefits":"","interestingFact":"","research":""}},"e228":{"name":"Kaliumhydrogensulfit","note":"Sulfit-Allergen.","detail":{"risks":"Ein Sulfit, das hauptsächlich in Wein verwendet wird. Gleiche Chemie und Allergen-Warnung wie E220.","benefits":"","interestingFact":"","research":""}},"e234":{"name":"Nisin","note":"Natürliches antibakterielles Peptid aus Fermentation.","detail":{"risks":"Ein Peptid, das von denselben Bakterien produziert wird, die Milch fermentieren – es stanzt Löcher in die Membranen von Verderbsbakterien. Wird in Käse und Konserven verwendet; wird wie jedes Protein verdaut.","benefits":"","interestingFact":"","research":""}},"e235":{"name":"Natamycin","note":"Antimykotikum für Käserinden; Debatte über Antibiotika-Klasse.","detail":{"risks":"Ein Antimykotikum aus Bodenbakterien, das auf Käserinden und Hüllen von Rohwürsten aufgetragen wird. Wird kaum aufgenommen, aber seine medizinische Nutzung als Antimykotikum hält eine Resistenzdebatte am Leben.","benefits":"","interestingFact":"","research":""}},"e239":{"name":"Hexamethylentetramin","note":"Formaldehyd-freisetzender Konservierungsstoff (nur für Provolone).","detail":{"risks":"In der EU nur für Provolone-Käse zugelassen. Es wirkt durch die langsame Freisetzung von Formaldehyd – der Grund, warum seine Verwendung so stark eingeschränkt ist.","benefits":"","interestingFact":"","research":""}},"e242":{"name":"Dimethyldicarbonat","note":"Entkeimungsmittel für Getränke, das sich vollständig abbaut.","detail":{"risks":"Kurz vor dem Abfüllen in Getränke injiziert, tötet es Mikroben ab und hydrolysiert innerhalb weniger Stunden vollständig zu winzigen Mengen Methanol und CO₂ – bis zum Trinken bleibt nichts davon übrig.","benefits":"","interestingFact":"","research":""}},"e249":{"name":"Kaliumnitrit","note":"Nitrit für Pökelwaren; bildet Nitrosamine, von der IARC klassifizierter Pfad.","detail":{"risks":"Der Kalium-Zwilling von Natriumnitrit (E250): hält Pökelfleisch rosa und frei von Botulismus, speist aber dieselbe Nitrosamin-Chemie, auf der die Einstufung von verarbeitetem Fleisch durch die IARC beruht.","benefits":"","interestingFact":"","research":""}},"e250":{"name":"Natriumnitrit","note":"Nitrit für Pökelwaren; bildet krebserregende Nitrosamine (IARC).","detail":{"risks":"Macht Schinken rosa und blockiert Botulismus – das tödlichste bekannte Toxin –, weshalb es weiterhin zugelassen ist. Zusammen mit Fleischeiweißen und Hitze bildet es jedoch Nitrosamine, der Hauptgrund, warum die IARC verarbeitetes Fleisch als krebserregend für den Menschen einstuft. Frankreich hat 2023 begonnen, es einzuschränken.","benefits":"","interestingFact":"","research":""}},"e251":{"name":"Natriumnitrat","note":"Wandelt sich in Nitrit um; dieselbe Nitrosamin-Bedenken.","detail":{"risks":"Die Speicherform der Pökelchemie: Bakterien im Fleisch (und in Ihrem Speichel) wandeln Nitrat stetig in Nitrit um und speisen denselben Nitrosamin-Pfad wie E250.","benefits":"","interestingFact":"","research":""}},"e252":{"name":"Kaliumnitrat","note":"Wandelt sich in Nitrit um; dieselbe Nitrosamin-Bedenken.","detail":{"risks":"Salpeter – seit dem Mittelalter zum Pökeln von Fleisch (und zur Herstellung von Schwarzpulver) verwendet. Bakterien wandeln es im Fleisch zu Nitrit um, wo die Nitrosamin-Chemie ihren Anfang nimmt.","benefits":"","interestingFact":"","research":""}},"e260":{"name":"Essigsäure","note":"Essig.","detail":{"risks":"Konzentrierte Essigsäure. Eines der ältesten Konservierungsmittel der Menschheitsgeschichte.","benefits":"","interestingFact":"","research":""}},"e261":{"name":"Kaliumacetat","note":"Essigsalz.","detail":{"risks":"Die Säure des Essigs an Kalium gebunden – ein Säureregulator, den Ihr Körper genau wie Essig behandelt.","benefits":"","interestingFact":"","research":""}},"e262":{"name":"Natriumacetate","note":"Essigsalz – der Geschmack von Salt & Vinegar-Chips.","detail":{"risks":"Natriumacetat verleiht Salt & Vinegar-Chips ihre Würze, ohne sie matschig zu machen. Außerdem die Verbindung in wiederverwendbaren Handwärmern.","benefits":"","interestingFact":"","research":""}},"e263":{"name":"Calciumacetat","note":"Essigsalz.","detail":{"risks":"An Calcium gebundene Essigsäure; dient gleichzeitig als Festigungsmittel. Wird wie Essig verstoffwechselt.","benefits":"","interestingFact":"","research":""}},"e270":{"name":"Milchsäure","note":"Natürliche Gärungssäure.","detail":{"risks":"Die Säure von Joghurt, Sauerteig und Muskelkater – entstanden durch Fermentation. Lebensmitteltaugliche Milchsäure wird durch Vergärung von Zucker mit derselben Bakterienfamilie wie im Joghurt gewonnen.","benefits":"","interestingFact":"","research":""}},"e280":{"name":"Propionsäure","note":"Brot-Konservierungsstoff; umstrittene Darmwirkungen bei hohen Dosen.","detail":{"risks":"Kommt natürlicherweise in Schweizer Käse vor (sie erzeugt das Aroma der Löcher) und in Ihrem eigenen Darm, wo Bakterien sie aus Ballaststoffen herstellen. Als Konservierungsmittel für Brot stoppt sie Schimmel; kleine Studien diskutieren Stoffwechselwirkungen bei hohen Dosen.","benefits":"","interestingFact":"","research":""}},"e281":{"name":"Natriumpropionat","note":"Schimmelhemmer für Brot.","detail":{"risks":"Das Natriumsalz der Propionsäure – die Verbindung, die Ihre eigenen Darmbakterien aus Ballaststoffen herstellen, hält abgepacktes Brot hier wochenlang schimmelfrei.","benefits":"","interestingFact":"","research":""}},"e282":{"name":"Calciumpropionat","note":"Brot-Konservierungsstoff; umstrittene Darmwirkungen bei hohen Dosen.","detail":{"risks":"Das weltweit häufigste Konservierungsmittel für Brot. Chemisch das gleiche Propionat, das Ihr Darm aus Ballaststoffen bildet; einige kleine Studien diskutieren Auswirkungen auf Appetit und Stoffwechsel bei hoher Aufnahme.","benefits":"","interestingFact":"","research":""}},"e283":{"name":"Kaliumpropionat","note":"Schimmelhemmer für Brot.","detail":{"risks":"Die Kaliumform der Propionat-Familie für natriumarme Brote. Derselbe Mechanismus zur Schimmelbekämpfung.","benefits":"","interestingFact":"","research":""}},"e284":{"name":"Borsäure","note":"In der EU nur für Kaviar zugelassen.","detail":{"risks":"Ein altes Konservierungsmittel, das inzwischen für alle EU-Lebensmittel verboten ist, bis auf eines: echten Stör-Kaviar, wo keine Alternative die Rogen konserviert. Eingeschränkt, da sich Bor anreichert.","benefits":"","interestingFact":"","research":""}},"e285":{"name":"Borax","note":"In der EU nur für Kaviar zugelassen.","detail":{"risks":"Das Natriumsalz der Borsäure, das deren einzige EU-Ausnahme teilt: Stör-Kaviar. Überall sonst ist es ein Reinigungsmittel-Inhaltsstoff, kein Lebensmittelzusatzstoff.","benefits":"","interestingFact":"","research":""}},"e290":{"name":"Kohlendioxid","note":"Die Bläschen in Kohlensäuregetränken.","detail":{"risks":"Ganz einfaches CO₂ – dasselbe Gas, das Sie ausatmen. In Getränken löst es sich als Kohlensäure und sorgt für das Sprudeln und Prickeln auf der Zunge; in Verpackungen verdrängt es Sauerstoff, sodass Lebensmittel langsamer verderben. Es verlässt Ihren Körper mit einem Rülpser.","benefits":"","interestingFact":"","research":""}},"e296":{"name":"Äpfelsäure","note":"Natürliche Fruchtsäure.","detail":{"risks":"Die feinsäuerliche Säure grüner Äpfel – ihr Name leitet sich von malum ab, dem lateinischen Wort für Apfel. Zudem sorgt sie für den sauren Kick in extrem sauren Süßigkeiten.","benefits":"","interestingFact":"","research":""}},"e297":{"name":"Fumarsäure","note":"Natürliche fruchtartige Säure.","detail":{"risks":"Kommt natürlich in Röhrlingen und Flechten vor; wird dort eingesetzt, wo Äpfel- oder Zitronensäure zu viel Feuchtigkeit aufnehmen würde, z. B. in Pulvermischungen.","benefits":"","interestingFact":"","research":""}},"e300":{"name":"Ascorbinsäure","note":"Vitamin C.","detail":{"risks":"Reines Vitamin C. In Lebensmitteln wirkt es als Sauerstofffänger – es opfert sich selbst der Oxidation, damit das Lebensmittel nicht braun wird. In Brot stärkt es das Gluten.","benefits":"","interestingFact":"","research":""}},"e301":{"name":"Natriumascorbat","note":"Vitamin-C-Salz.","detail":{"risks":"An Natrium gebundenes Vitamin C für eine bessere Löslichkeit – Standard bei Pökelwaren, wo es die Umrötung beschleunigt und die Nitrosaminbildung unterdrückt.","benefits":"","interestingFact":"","research":""}},"e302":{"name":"Calciumascorbat","note":"Vitamin-C-Salz.","detail":{"risks":"Vitamin C in seiner sanfteren Calciumform, verwendet, um geschnittenes Obst am Braunwerden zu hindern. Ernährungsphysiologisch ist es weiterhin einfach Vitamin C plus etwas Calcium.","benefits":"","interestingFact":"","research":""}},"e304":{"name":"Ascorbylpalmitat","note":"Fettlösliches Vitamin C.","detail":{"risks":"An eine Fettsäure gebundenes Vitamin C, damit es Öle und Fette vor dem Ranzigwerden schützen kann, wo normales Vitamin C nicht hingelangt.","benefits":"","interestingFact":"","research":""}},"e306":{"name":"Tocopherole","note":"Vitamin E.","detail":{"risks":"Aus Pflanzenölen extrahiertes natürliches Vitamin E; schützt Fette auf dieselbe Weise vor dem Ranzigwerden, wie es Ihre Zellmembranen schützt.","benefits":"","interestingFact":"","research":""}},"e307":{"name":"Alpha-Tocopherol","note":"Vitamin E.","detail":{"risks":"Die spezifische Form von Vitamin E, die Ihr Körper bevorzugt, aus Gründen der Gleichmäßigkeit synthetisch hergestellt. Gleicher Antioxidationsjob wie E306.","benefits":"","interestingFact":"","research":""}},"e308":{"name":"Gamma-Tocopherol","note":"Vitamin E.","detail":{"risks":"Die Vitamin-E-Form, die in Soja- und Maiskeimöl am häufigsten vorkommt und Fette vor Oxidation schützt.","benefits":"","interestingFact":"","research":""}},"e309":{"name":"Delta-Tocopherol","note":"Vitamin E.","detail":{"risks":"Das hitzebeständigste Mitglied der Vitamin-E-Familie, bevorzugt für Frittierfette.","benefits":"","interestingFact":"","research":""}},"e310":{"name":"Propylgallat","note":"Synthetisches Antioxidationsmittel; Endokrin-Debatte.","detail":{"risks":"Ein synthetisches Antioxidationsmittel für Fette und Öle. Nagerstudien warfen (umstrittene) Fragen zu endokrinen Effekten und Tumoren auf; die EFSA hat die zulässige Tagesdosis 2014 neu festgelegt, und es taucht in modernen Rezepturen immer seltener auf.","benefits":"","interestingFact":"","research":""}},"e311":{"name":"Octylgallat","note":"Synthetisches Antioxidationsmittel; begrenzte Datenlage.","detail":{"risks":"Ein Gallat-Antioxidationsmittel, dessen EU-Zulassung 2018 mangels Sicherheitsdaten auslief – findet man es auf einem Etikett, deutet das meist auf eine alte Rezeptur oder einen Import hin.","benefits":"","interestingFact":"","research":""}},"e312":{"name":"Dodecylgallat","note":"Synthetisches Antioxidationsmittel; begrenzte Datenlage.","detail":{"risks":"Das langkettigste Gallat; wie bei E311 wurde seine EU-Zulassung 2018 gestrichen, da die Hersteller keine unterstützenden Daten einreichten.","benefits":"","interestingFact":"","research":""}},"e315":{"name":"Erythorbinsäure","note":"Spiegelmolekül von Vitamin C, reine Antioxidationswirkung.","detail":{"risks":"Ein spiegelbildliches Isomer von Vitamin C: gleiche Antioxidationskraft im Lebensmittel, aber fast keine Vitaminaktivität im Körper.","benefits":"","interestingFact":"","research":""}},"e316":{"name":"Natriumerythorbat","note":"In Pökelwaren verwendetes Antioxidationsmittel.","detail":{"risks":"Beschleunigt das Pökeln und reduziert den Nitritbedarf in verarbeitetem Fleisch – sein Vorhandensein bedeutet meist weniger Nitrit, nicht mehr Risiko. Der alte Mythos, es werde „aus Regenwürmern hergestellt“, ist genau das: ein Mythos (es wird aus Zucker hergestellt).","benefits":"","interestingFact":"","research":""}},"e319":{"name":"TBHQ","note":"Synthetisches Antioxidationsmittel; Studien zu Immunwirkungen umstritten.","detail":{"risks":"Tertiär-Butylhydrochinon, ein aus Erdöl gewonnenes Antioxidationsmittel in Frittierölen und Instantnudeln. Hochdosierte Tierstudien diskutieren Immun- und Tumoreffekte; die EFSA hält an einer strengen Höchstmenge fest.","benefits":"","interestingFact":"","research":""}},"e320":{"name":"BHA","note":"Mögliches Karzinogen (IARC 2B); endokrine Bedenken.","detail":{"risks":"Butylhydroxyanisol, ein synthetisches Antioxidationsmittel. Die IARC stuft es aufgrund von Vormagentumoren bei Nagetieren als „möglichst krebserregend“ ein; es steht auch auf der EU-Prüfliste für endokrine Disruptoren. Vitamin E erledigt denselben Job.","benefits":"","interestingFact":"","research":""}},"e321":{"name":"BHT","note":"Umstrittene Krebserzeugendheit und endokrine Wirkungen.","detail":{"risks":"Der chemische Verwandte von BHA, der auch in Kosmetika und Kerosin verwendet wird. Die Datenlage ist gemischter als bei BHA – einige Studien deuten sogar auf schützende Effekte hin –, aber die Endokrin-Debatte hält es im Gespräch.","benefits":"","interestingFact":"","research":""}},"e322":{"name":"Lecithine","note":"Natürlicher Emulgator aus Soja oder Sonnenblumen.","detail":{"risks":"Das Molekül, das Fett und Wasser verbindet – ein Ende liebt Wasser, das andere Öl. Gewonnen aus Sojabohnen, Sonnenblumenkernen oder Eigelb (Mayonnaise funktioniert wegen Eilecithin). Ihre eigenen Zellmembranen bestehen teilweise daraus.","benefits":"","interestingFact":"","research":""}},"e325":{"name":"Natriumlactat","note":"Salz der Milchsäure.","detail":{"risks":"An Natrium gebundene Fermentationssäure – ein Feuchthaltemittel und mildes Konservierungsmittel in Fleisch- und Backwaren. Ihre Muskeln produzieren bei Sport dasselbe Lactat.","benefits":"","interestingFact":"","research":""}},"e326":{"name":"Kaliumlactat","note":"Salz der Milchsäure.","detail":{"risks":"Die Kaliumform von Lactat, häufig in natriumarmen Fleischprodukten. Wird genauso verstoffwechselt wie das vom eigenen Körper produzierte Lactat.","benefits":"","interestingFact":"","research":""}},"e327":{"name":"Calciumlactat","note":"Salz der Milchsäure, auch eine Calciumquelle.","detail":{"risks":"Milchsäure als Calciumträger – verwendet, um Dosengemüse zu festigen und Lebensmittel mit Calcium anzureichern. Es ist der knusprige Kristall, den man manchmal auf gereiftem Cheddar sieht.","benefits":"","interestingFact":"","research":""}},"e330":{"name":"Zitronensäure","note":"Allgegenwärtige natürliche Säure.","detail":{"risks":"Die Säure von Zitronen, industriell hergestellt durch Fermentation von Zucker mit einem Schimmelpilz (ein 1917 entdecktes Verfahren). Jede Zelle Ihres Körpers stellt kontinuierlich Zitronensäure her und verbrennt sie – der „Zitronensäurezyklus“ ist die Art und Weise, wie Sie Energie erzeugen. Das hartnäckige Gerücht „E330 verursacht Krebs“ geht auf ein Faltblatt mit einer Falschmeldung aus den 1970er-Jahren zurück, eine der ältesten Fehlinformationen über Lebensmittel.","benefits":"","interestingFact":"","research":""}},"e331":{"name":"Natriumcitrate","note":"Salz der Zitronensäure.","detail":{"risks":"Das Salz der Zitronensäure – es sorgt dafür, dass Schmelzkäse glatt schmilzt, anstatt sich zu trennen, indem es das Calcium lockert, das die Kaseinproteine zusammenhält.","benefits":"","interestingFact":"","research":""}},"e332":{"name":"Kaliumcitrate","note":"Salz der Zitronensäure.","detail":{"risks":"Citrat, das Kalium statt Natrium trägt; ein Säurepuffer, der im selben Energiezyklus verstoffwechselt wird wie die Zitronensäure selbst.","benefits":"","interestingFact":"","research":""}},"e333":{"name":"Calciumcitrate","note":"Salz der Zitronensäure, auch eine Calciumquelle.","detail":{"risks":"An Calcium gebundenes Citrat – Säureregulator, Festigungsmittel und die Calciumform, die in vielen Nahrungsergänzungsmitteln verwendet wird, weil sie gut aufgenommen wird.","benefits":"","interestingFact":"","research":""}},"e334":{"name":"Weinsäure","note":"Natürliche Traubensäure.","detail":{"risks":"Die Säure von Trauben und Wein – die Kristalle, die sich manchmal in einer Weinflasche befinden, sind ihr Kaliumsalz. Die klassische Säure von Backpulver.","benefits":"","interestingFact":"","research":""}},"e335":{"name":"Natriumtartrate","note":"Salz der Traubensäure.","detail":{"risks":"An Natrium gebundene Traubensäure, ein Säureregulator, der meist in Marmeladen und Gelees zu finden ist. Wird weitgehend nicht aufgenommen.","benefits":"","interestingFact":"","research":""}},"e336":{"name":"Kaliumtartrate","note":"Weinstein.","detail":{"risks":"Weinstein – im wörtlichen Sinne von der Innenseite von Weinfässern geschabt. Der traditionelle Partner von Natron in Backpulver und der Stabilisator von geschlagenem Eiweiß.","benefits":"","interestingFact":"","research":""}},"e337":{"name":"Natriumkaliumtartrat","note":"Seignettesalz, aus der Weinherstellung.","detail":{"risks":"Seignettesalz, erstmals 1675 von einem französischen Apotheker hergestellt. Eine Berühmtheit der Kristallographie (es war das erste Material, bei dem Piezoelektrizität nachgewiesen wurde), das seine Arbeit still und leise als Säureregulator verrichtet.","benefits":"","interestingFact":"","research":""}},"e338":{"name":"Phosphorsäure","note":"Cola-Säure; hohe Phosphataufnahme mit kardiovaskulären Bedenken verknüpft.","detail":{"risks":"Das, was Cola ihren scharfen Geschmacks-Kick gibt (und ihren Partytrick zur Rostentfernung). Die Sorge gilt nicht einer akuten Toxizität, sondern der Gesamtphosphatbelastung: Die Neubewertung der EFSA aus dem Jahr 2019 ergab, dass Vielverbrauchende die sichere Aufnahme überschreiten können, und überschüssiges Phosphat wird mit einer Belastung von Gefäßen und Nieren in Verbindung gebracht.","benefits":"","interestingFact":"","research":""}},"e339":{"name":"Natriumphosphate","note":"Hohe Phosphataufnahme mit kardiovaskulären Bedenken verknüpft.","detail":{"risks":"Vielseitige Phosphatsalze – Feuchtigkeitsbindung, Schmelzen, Pufferung. Einzeln sicher, aber sie summieren sich: Die EFSA-Bewertung von 2019 warnte, dass die Gesamtphosphataufnahme aus verarbeiteten Lebensmitteln die sicheren Werte überschreiten kann.","benefits":"","interestingFact":"","research":""}},"e340":{"name":"Kaliumphosphate","note":"Bedenken hinsichtlich hoher Phosphataufnahme.","detail":{"risks":"Der Kalium-Zweig der Phosphatfamilie, häufig in Sportgetränken und Schmelzkäse. Gleiche Vorsicht bezüglich der kumulativen Phosphatbelastung wie bei den Verwandten.","benefits":"","interestingFact":"","research":""}},"e341":{"name":"Calciumphosphate","note":"Phosphat; moderate Aufnahme akzeptabel.","detail":{"risks":"Das Mineral, aus dem Ihre Knochen und Zähne bestehen, verwendet als Backtriebmittel und zur Calciumanreicherung. Das mildeste Mitglied der Phosphatfamilie – das Calcium gleicht die Bedenken hinsichtlich der Phosphatbelastung teilweise aus.","benefits":"","interestingFact":"","research":""}},"e343":{"name":"Magnesiumphosphate","note":"Phosphat; moderate Aufnahme akzeptabel.","detail":{"risks":"Magnesiumhaltiges Phosphat, das als Trennmittel und Säureregulator eingesetzt wird. Trägt zur Phosphatbelastung bei, aber die typischen Einsatzmengen sind winzig.","benefits":"","interestingFact":"","research":""}},"e350":{"name":"Natriummalate","note":"Salz der Apfelsäure.","detail":{"risks":"An Natrium gebundene Apfelsäure – ein Säurepuffer, der wie die Apfelsäure in jedem Apfel verstoffwechselt wird.","benefits":"","interestingFact":"","research":""}},"e351":{"name":"Kaliummalat","note":"Salz der Apfelsäure.","detail":{"risks":"Die Kaliumform der Apfelsäure, ein selten verwendeter Säureregulator ohne bekannte Bedenken.","benefits":"","interestingFact":"","research":""}},"e352":{"name":"Calciummalate","note":"Salz der Apfelsäure.","detail":{"risks":"Calciumhaltige Apfelsäure; Säureregulator und Festigungsmittel, das wie Fruchtsäure verstoffwechselt wird.","benefits":"","interestingFact":"","research":""}},"e353":{"name":"Metatartarsäure","note":"Weinstabilisator aus Traubensäure.","detail":{"risks":"In kurze Ketten verknüpfte Traubensäuremoleküle; Winzer setzen sie ein, um das Entstehen harmloser Tartratkristalle in der Flasche zu stoppen. Sie wandelt sich langsam wieder in normale Weinsäure um.","benefits":"","interestingFact":"","research":""}},"e355":{"name":"Adipinsäure","note":"Synthetische Säure für Pulver.","detail":{"risks":"Eine saure Verbindung, die Feuchtigkeit abweist und sich daher ideal für Getränkepulver und Götterspeisepulver eignet. Industriell ist sie eher als Nylon-Vorprodukt bekannt; die Verwendung in Lebensmitteln ist ein Rundungsfehler der Produktion.","benefits":"","interestingFact":"","research":""}},"e363":{"name":"Bernsteinsäure","note":"Fermentationssäure.","detail":{"risks":"Eine Säure aus demselben Energiezyklus wie Citrat – Ihre Zellen stellen sie ständig her. In Lebensmitteln verleiht sie Pulverdesserts eine frische Säure; der Name stammt von Bernstein (succinum), aus dem sie erstmals destilliert wurde.","benefits":"","interestingFact":"","research":""}},"e380":{"name":"Triammoniumcitrat","note":"Citrat-Säureregulator.","detail":{"risks":"Mit Ammonium neutralisierte Citronensäure, die zur Säurepufferung in Schmelzkäse verwendet wird. Das Ammonium geht in den normalen Stickstoffhaushalt Ihres Körpers ein.","benefits":"","interestingFact":"","research":""}},"e385":{"name":"Calcium-Dinatrium-EDTA","note":"Chelatbildner; Bedenken hinsichtlich der Mineralstoffabsorption bei hohen Dosen.","detail":{"risks":"Eine molekulare Kralle, die Spurenmetalle greift, sodass diese Ranzigkeit oder Verfärbungen nicht katalysieren können (hält Kichererbsen in der Dose hell). Dieselbe Eigenschaft kann Mineralstoffe aus der Nahrung binden, daher die Dosisgrenzen. Wird auch medizinisch bei Schwermetallvergiftungen eingesetzt.","benefits":"","interestingFact":"","research":""}},"e392":{"name":"Rosmarinextrakt","note":"Natürliches Kräuter-Antioxidationsmittel.","detail":{"risks":"Konzentrierte Antioxidantien (Carnosinsäure) aus Rosmarinblättern – der moderne Clean-Label-Ersatz für BHA/BHT.","benefits":"","interestingFact":"","research":""}},"e400":{"name":"Alginsäure","note":"Verdickungsmittel aus Braunalgen.","detail":{"risks":"Das Strukturgummi von Braunalgen – das, was Algen unter Wasser flexibel hält. Im Darm verhält es sich wie löslicher Ballaststoff.","benefits":"","interestingFact":"","research":""}},"e401":{"name":"Natriumalginat","note":"Algen-Verdickungsmittel.","detail":{"risks":"Aus Braunalgen; berühmt als Zutat für die \\"Sphärisierung\\" in der Molekularküche, die Flüssigkeiten in kaviarähnliche Perlen verwandelt. Auch das Gel in vielen Mitteln gegen Sodbrennen.","benefits":"","interestingFact":"","research":""}},"e402":{"name":"Kaliumalginat","note":"Algen-Verdickungsmittel.","detail":{"risks":"Die Kaliumform des Braunalgenalginats; ein Verdickungsmittel aus löslichen Ballaststoffen ohne bekannte Bedenken.","benefits":"","interestingFact":"","research":""}},"e404":{"name":"Calciumalginat","note":"Algen-Geliermittel.","detail":{"risks":"Braunalgenalginat, das bereits mit Calcium angereichert ist, das es zum Gelieren bringt – wird wegen desselben Gelier-Effekts auch in Wundauflagen verwendet.","benefits":"","interestingFact":"","research":""}},"e405":{"name":"Propylenglycolalginat","note":"Modifiziertes Algen-Verdickungsmittel (Bierschaum, Dressings).","detail":{"risks":"Braunalgenalginat, das modifiziert wurde, um Säure zu überstehen – hält den Bierschaum stabil und Salatdressings dickflüssig. Der Propylenglycol-Teil wird freigesetzt und harmlos verstoffwechselt.","benefits":"","interestingFact":"","research":""}},"e406":{"name":"Agar-Agar","note":"Algen-Geliermittel.","detail":{"risks":"Aus Rotalgen – 1658 in Japan entdeckt und das Standardgel mikrobiologischer Labore weltweit. Geliert fester als Gelatine und bleibt bei Raumtemperatur fest; rein pflanzlich.","benefits":"","interestingFact":"","research":""}},"e407":{"name":"Carrageen","note":"Umstrittener Zusammenhang mit Darmentzündungen in abgebauter Form.","detail":{"risks":"Aus Irländischem Moos extrahiert und seit Jahrhunderten in irischen Milchpuddings verwendet. Die Debatte: Abgebautes Carrageen (nicht die Lebensmittelform) führt bei Tieren zu Darmentzündungen; ob Magensäure die Lebensmittelform abbaut, ist weiterhin umstritten. Die EFSA erneuerte 2018 die Zulassung, forderte jedoch weitere Daten an.","benefits":"","interestingFact":"","research":""}},"e407a":{"name":"Verarbeitete Eucheuma-Algen","note":"Semi-raffiniertes Carrageen; dieselbe Debatte.","detail":{"risks":"Ein weniger gereinigtes Carrageen direkt aus kultivierten Eucheuma-Algen, das noch etwas Cellulose enthält. Es teilt die Debatte über den Carrageen-Abbau Punkt für Punkt.","benefits":"","interestingFact":"","research":""}},"e410":{"name":"Johannisbrotkernmehl","note":"Natürliches Karuben-Verdickungsmittel.","detail":{"risks":"Gemahlene Samen des Johannisbrotbaums. Fun Fact: Das gleichmäßige Gewicht von Johannisbrotsamen gab uns das Juwelier-\\"Karat\\".","benefits":"","interestingFact":"","research":""}},"e412":{"name":"Guarkernmehl","note":"Natürliches Verdickungsmittel.","detail":{"risks":"Gemahlene Guarbohnen aus Indien – achtfache Verdickungskraft von Maisstärke. Es ist löslicher Ballaststoff; sehr große Mengen wirken wie jeder Überschuss an Ballaststoffen.","benefits":"","interestingFact":"","research":""}},"e413":{"name":"Traganth","note":"Natürlicher Baumsaft-Gummi.","detail":{"risks":"Getrockneter Pflanzensaft nahöstlicher Tragantsträucher, der seit der Antike geerntet wird – Theophrastus beschrieb ihn 300 BC. Der traditionelle Festiger für Zuckerblumen auf Hochzeitstorten.","benefits":"","interestingFact":"","research":""}},"e414":{"name":"Gummi arabicum","note":"Natürliches Gummi arabicum.","detail":{"risks":"Pflanzensaft des Akazienbaums, ähnlich wie Ahornsirup hauptsächlich im Sudan geerntet. Er hält Zitrusöle in Limonade in Schwebe und verleiht Weingummis ihren Biss. Zählt als löslicher Ballaststoff.","benefits":"","interestingFact":"","research":""}},"e415":{"name":"Xanthan","note":"Durch Fermentation gewonnenes Verdickungsmittel.","detail":{"risks":"Hergestellt durch Fermentation von Zucker mit Xanthomonas-Bakterien. Seine Superkraft ist die \\"Scherverdünnung\\": im Ruhezustand dickflüssig, beim Schütteln flüssig – weshalb Salatdressing gießbar ist, sich aber nicht entmischt. Ein Grundnahrungsmittel des glutenfreien Backens.","benefits":"","interestingFact":"","research":""}},"e416":{"name":"Karayagummi","note":"Baumgummi; mildes Abführmittel bei hohen Dosen.","detail":{"risks":"Pflanzensaft des indischen Sterculia-Baums. Größtenteils unverdaulicher Ballaststoff – was auch der Grund ist, warum große Mengen abführend wirken.","benefits":"","interestingFact":"","research":""}},"e417":{"name":"Taragummi","note":"Natürliches Samen-Verdickungsmittel.","detail":{"risks":"Gemahlene Samen des peruanischen Tarabaums – ein milderer Verwandter von Guar- und Johannisbrotkernmehl, der sich wie löslicher Ballaststoff verhält.","benefits":"","interestingFact":"","research":""}},"e418":{"name":"Gellan","note":"Durch Fermentation gewonnenes Geliermittel.","detail":{"risks":"Wird wie Xanthan durch bakterielle Fermentation hergestellt, geliert jedoch, anstatt nur zu verdicken – es hält das Fruchtfleisch in manchen Säften in Schwebe und lässt vegane Gelees mit einem bemerkenswert klaren Biss fest werden.","benefits":"","interestingFact":"","research":""}},"e420":{"name":"Sorbit","note":"Polyol-Süßungsmittel; abführend bei hohen Dosen.","detail":{"risks":"Ein Zuckeralkohol, der natürlich in Vogelbeeren und Birnen vorkommt. Hat halb so viele Kalorien wie Zucker und ist zahnschonend, aber unresorbiertes Sorbit fermentiert im Dickdarm – der Grund, warum zuckerfreie Kaugummipackungen vor abführenden Wirkungen warnen.","benefits":"","interestingFact":"","research":""}},"e421":{"name":"Mannit","note":"Polyol; abführend bei hohen Dosen.","detail":{"risks":"Ein Zuckeralkohol, der ursprünglich aus Manna-Eschen gewonnen wurde (daher der biblische Name). Wird kaum aufgenommen, sodass die übliche Verdauungswarnung für Polyole gilt; sein kühlender Schmelz sorgt für die Frische in manchen Pfefferminzbonbons.","benefits":"","interestingFact":"","research":""}},"e422":{"name":"Glycerin","note":"Feuchthaltemittel, das Lebensmittel feucht hält.","detail":{"risks":"Das Grundgerüstmolekül aller Fette, das bei der Fettverdauung freigesetzt wird. In Lebensmitteln bindet es Feuchtigkeit – deshalb bleiben Proteinriegel monatelang weich.","benefits":"","interestingFact":"","research":""}},"e425":{"name":"Konjak","note":"In Gelee-Süßwaren eingeschränkt (Erstickungsgefahr).","detail":{"risks":"Wurzelmehl hinter den japanischen Shirataki-Nudeln. Sein Gel ist so stark und hitzebeständig, dass die EU es nach Erstickungsfällen in Mini-Gelee-Kapseln verboten hat – als Lebensmittelverdickungsmittel in normalen Formaten ist es unbedenklich.","benefits":"","interestingFact":"","research":""}},"e426":{"name":"Sojabohnen-Hemicellulose","note":"Soja-Ballaststoff-Emulgator.","detail":{"risks":"Aus Soja-Pulp extrahierter löslicher Ballaststoff, der saure Milchgetränke am Gerinnen hindert. Verbraucher mit Soja-Allergie sollten die Quelle beachten.","benefits":"","interestingFact":"","research":""}},"e432":{"name":"Polysorbat 20","note":"Synthetischer Emulgator; Mikrobiom-Studien umstritten.","detail":{"risks":"Der kleinste der Polysorbat-Detergens-Emulgatoren. Die Familie geriet ins Visier, nachdem Mäusestudien aus dem Jahr 2015 eine Ausdünnung der Darmschleimhaut zeigten; die Relevanz für den Menschen wird noch untersucht.","benefits":"","interestingFact":"","research":""}},"e433":{"name":"Polysorbat 80","note":"Synthetischer Emulgator; Mikrobiom-Studien umstritten.","detail":{"risks":"Ein spülmittelähnlicher Emulgator (Speiseeis, Soßen). Eine viel zitierte Nature 2015 Studie ergab, dass er bei Mäusen die schützende Schleimhaut des Darms ausdünnte und Entzündungen förderte – die Relevanz für den Menschen wird noch untersucht, brachte Emulgatoren aber ins Blickfeld der Forschung.","benefits":"","interestingFact":"","research":""}},"e434":{"name":"Polysorbat 40","note":"Synthetischer Emulgator; Mikrobiom-Studien umstritten.","detail":{"risks":"Ein mittelkettiger Polysorbat-Emulgator. Teilt die Mikrobiom-Debatte der Familie, die durch die Nature 2015 Mäusestudie eröffnet wurde.","benefits":"","interestingFact":"","research":""}},"e435":{"name":"Polysorbat 60","note":"Synthetischer Emulgator; Mikrobiom-Studien umstritten.","detail":{"risks":"Das Polysorbat, das am häufigsten in Backcremes und Schlagcremes verwendet wird – es verhindert, dass Fetttröpfchen verschmelzen. Wie seine Verwandten ist es Teil der Forschung zum Darm-Mikrobiom, die durch die Nature-Studie von 2015 angestoßen wurde.","benefits":"","interestingFact":"","research":""}},"e436":{"name":"Polysorbat 65","note":"Synthetischer Emulgator; Mikrobiom-Studien umstritten.","detail":{"risks":"Das schwerste Polysorbat, das hauptsächlich in Speiseeis vorkommt. Gleiche Familie, gleiche offene Fragen zum Mikrobiom.","benefits":"","interestingFact":"","research":""}},"e440":{"name":"Pektin","note":"Natürliches Fruchtgeliermittel.","detail":{"risks":"Das natürliche Gel aus Äpfeln und Zitrusfruchtschalen – das, was Marmelade gelieren lässt. Es ist ein löslicher Ballaststoff und der Grund, warum Oma Apfelscheiben in flüssige Marmelade gegeben hat.","benefits":"","interestingFact":"","research":""}},"e441":{"name":"Gelatine","note":"Geliermittel tierischen Ursprungs.","detail":{"risks":"Kollagen aus Haut und Knochen von Tieren, aufgespalten in ein Protein, das genau bei Mundtemperatur schmilzt – das „Zerschmelzen im Mund“ von Gummibärchen ist eine Materialeigenschaft, kein Geschmack.","benefits":"","interestingFact":"","research":""}},"e442":{"name":"Ammoniumphosphatide","note":"Schokoladenemulgator, Lecithin-Alternative.","detail":{"risks":"Ein synthetischer Verwandter von Lecithin aus Rapsöl, der in Schokolade dieselbe Aufgabe erfüllt: Sie flüssiger zu machen, mit weniger Kakaobutter. Wird wie ganz normales Fett plus einer Spur Phosphat verdaut.","benefits":"","interestingFact":"","research":""}},"e444":{"name":"Saccharoseacetatisobutyrat","note":"Trübungsstabilisator für Zitrusgetränke.","detail":{"risks":"Ein beschwertes Molekül auf Zuckerbasis, das Zitrus-Aromaöle in Erfrischungsgetränken gleichmäßig trüb hält, anstatt sich am Flaschenhals abzusetzen.","benefits":"","interestingFact":"","research":""}},"e445":{"name":"Glycerinester aus Wurzelharz","note":"Hält Zitrusöle in Getränken gemischt.","detail":{"risks":"Gereinigtes Kiefernharz (dasselbe Grundmaterial, das Geiger auf den Bogen reiben), verestert, um Zitrus-Aromaöle in Sportgetränken in Schwebe zu halten.","benefits":"","interestingFact":"","research":""}},"e450":{"name":"Diphosphate","note":"Phosphat-Zusatzstoff; Herz-Kreislauf-Debatte bei hoher Aufnahme.","detail":{"risks":"Treibmittel in Backpulver und Wasserbinder in verarbeitetem Fleisch und Käse. Für sich genommen sicher, aber die EFSA-Neubewertung von 2019 warnte davor, dass die Gesamt-Phosphataufnahme aus allen Zusatzstoffquellen bei Vielverbrauchern die sicheren Mengen überschreiten kann – Phosphate sind das „versteckte Salz“ hochverarbeiteter Lebensmittel.","benefits":"","interestingFact":"","research":""}},"e451":{"name":"Triphosphate","note":"Bedenken wegen Phosphat-Zusatzstoff.","detail":{"risks":"Dreigliedrige Phosphatketten, die gepökeltes Fleisch und Fisch Wasser (und Gewicht) halten lassen. Sie tragen zur kumulativen Phosphatbelastung bei, die die EFSA 2019 hervorgehoben hat.","benefits":"","interestingFact":"","research":""}},"e452":{"name":"Polyphosphate","note":"Bedenken wegen Phosphat-Zusatzstoff.","detail":{"risks":"Lange Phosphatketten – die stärksten Wasserbinder der Familie, häufig in Glasuren für gefrorene Meeresfrüchte und Schmelzkäse. Gleiche Vorsicht bezüglich der kumulativen Aufnahme wie bei den anderen Phosphaten.","benefits":"","interestingFact":"","research":""}},"e459":{"name":"Beta-Cyclodextrin","note":"Aromaträger aus Stärke.","detail":{"risks":"Ein Ring aus Glukoseeinheiten mit einer hohlen Mitte, der Aromamoleküle einfängt und sie langsam freisetzt – molekulare Verpackung aus Stärke.","benefits":"","interestingFact":"","research":""}},"e460":{"name":"Cellulose","note":"Pflanzenfaser.","detail":{"risks":"Gereinigte Pflanzenfaser, meist aus Holzschliff – unverdaulicher Füllstoff, der Cremigkeit verleiht und geriebenen Käse am Verklumpen hindert.","benefits":"","interestingFact":"","research":""}},"e461":{"name":"Methylcellulose","note":"Modifizierte Pflanzenfaser; geliert in der Hitze.","detail":{"risks":"Chemisch modifizierte Cellulose mit einem besonderen Kunststück: Sie geliert beim Erhitzen und schmilzt beim Abkühlen – das Gegenteil von Gelatine. Sie hält pflanzliche Burger auf dem Grill zusammen.","benefits":"","interestingFact":"","research":""}},"e463":{"name":"Hydroxypropylcellulose","note":"Modifizierte Pflanzenfaser.","detail":{"risks":"Für mehr Flexibilität modifizierte Cellulose, hauptsächlich als Überzugsmittel und Bindemittel. Passiert wie jeder Ballaststoff unverdaut den Darm.","benefits":"","interestingFact":"","research":""}},"e464":{"name":"Hypromellose","note":"Modifizierte Pflanzenfaser (auch vegetarische Kapseln).","detail":{"risks":"Die modifizierte Cellulose, aus der vegetarische Arzneimittelkapseln bestehen; in Lebensmitteln dickt sie an und stabilisiert. Unverdaulich und wird nicht aufgenommen.","benefits":"","interestingFact":"","research":""}},"e465":{"name":"Ethylmethylcellulose","note":"Modifizierte Pflanzenfaser.","detail":{"risks":"Eine doppelt modifizierte Cellulose, die zur Stabilisierung von Schäumen und Emulsionen verwendet wird. Wie der Rest der Cellulose-Familie wird sie als Ballaststoff wieder ausgeschieden.","benefits":"","interestingFact":"","research":""}},"e466":{"name":"Carboxymethylcellulose","note":"Emulgator mit umstrittenen Auswirkungen auf das Darm-Mikrobiom.","detail":{"risks":"Modifizierte Cellulose, die von Speiseeis bis Zahnpasta überall verwendet wird. Zusammen mit Polysorbat 80 Gegenstand der Nature-Mikrobiom-Studie von 2015; eine kleine Humanstudie von 2021 zeigte ebenfalls Veränderungen der Darmbakterien, weshalb weiter aktiv daran geforscht wird.","benefits":"","interestingFact":"","research":""}},"e468":{"name":"Vernetzte Carboxymethylcellulose","note":"Modifizierte Cellulose.","detail":{"risks":"Carboxymethylcellulose, deren Ketten miteinander verknüpft sind, sodass sie quillt statt sich aufzulösen – meist ein Tablettensprengmittel, gelegentlich in Lebensmitteln. Wird nicht aufgenommen.","benefits":"","interestingFact":"","research":""}},"e470a":{"name":"Salze der Speisefettsäuren","note":"Seifenähnliche Salze von Speisefetten.","detail":{"risks":"Gewöhnliche Fettmoleküle, die an Natrium, Kalium oder Calcium gebunden sind – technisch gesehen Seife, praktisch ein Trenn- und Rieselhilfsmittel, das wie Fett verdaut wird.","benefits":"","interestingFact":"","research":""}},"e470b":{"name":"Magnesiumsalze der Speisefettsäuren","note":"Fettsalz als Rieselhilfe.","detail":{"risks":"Magnesiumstearat, bekannt aus nahezu jeder Tablette, die jemals hergestellt wurde – es verhindert, dass Pulver an Maschinen kleben bleibt. Wird als Fett plus einen Hauch von Magnesium verdaut.","benefits":"","interestingFact":"","research":""}},"e471":{"name":"Mono- und Diglyceride","note":"Häufiger Emulgator; kann Transfettsäuren enthalten.","detail":{"risks":"Der meistverwendete Emulgator der Welt – Teil-Fettmoleküle, die eine Brücke zwischen Öl und Wasser schlagen, Brot weich und Margarine geschmeidig halten. Chemisch identisch mit normalen Fettverdauungsprodukten; der Haken ist, dass die industrielle Herstellung Spuren von Transfetten hinterlassen kann, die auf dem Etikett unsichtbar sind.","benefits":"","interestingFact":"","research":""}},"e472a":{"name":"Essigsäureester von Glyceriden","note":"Emulgator für Überzüge und Schaumspeisen.","detail":{"risks":"E471-Emulgator mit gebundener Essigsäure – verwendet in Kuchenglasuren und Sprühsahne. Wird in gewöhnliches Fett und Essig verdaut.","benefits":"","interestingFact":"","research":""}},"e472b":{"name":"Milchsäureester von Glyceriden","note":"Emulgator für Schlagsahne.","detail":{"risks":"E471 mit gebundener Milchsäure, stabilisiert Schlagcremes. Baut sich zu normalen Fettverdauungsprodukten plus Lactat ab.","benefits":"","interestingFact":"","research":""}},"e472c":{"name":"Citronensäureester von Glyceriden","note":"Emulgator, auch Spritzschutz in Fetten.","detail":{"risks":"E471 mit gebundener Citronensäure; verhindert, dass Margarine in der Pfanne spritzt. Wird in Fett und Citrat verdaut – beides alltägliche Stoffwechselprodukte.","benefits":"","interestingFact":"","research":""}},"e472e":{"name":"DATEM","note":"Brot-Emulgator, im Allgemeinen gut verträglich.","detail":{"risks":"Diacetylweinsäureester von Mono- und Diglyceriden – der Kleberfestiger des Industriebäckers, der Supermarktbrot seine gleichmäßige Krume und sein Volumen verleiht.","benefits":"","interestingFact":"","research":""}},"e473":{"name":"Zuckerester","note":"Emulgator, bei typischen Dosierungen akzeptabel.","detail":{"risks":"Zucker, gebunden an Fettsäuren – ein so milder Emulgator, dass verwandte Verbindungen als Zutaten für Säuglingsnahrung erforscht werden. Spaltet sich während der Verdauung wieder in Zucker und Fett auf.","benefits":"","interestingFact":"","research":""}},"e475":{"name":"Polyglycerinester","note":"Kuchen-Emulgator.","detail":{"risks":"Ketten von Glycerin, die Fettsäuren tragen und Luft in Industriekuchen schlagen, sodass weniger Ei benötigt wird. Wird wie Fett verdaut.","benefits":"","interestingFact":"","research":""}},"e476":{"name":"Polyglycerin-Polyricinoleat","note":"Schokoladenemulgator (PGPR); laut EFSA bei typischen Dosierungen akzeptabel.","detail":{"risks":"Hergestellt aus Rizinusöl sorgt PGPR dafür, dass flüssige Schokolade besser fließt, sodass Hersteller weniger teure Kakaobutter verwenden können. Seine Anwesenheit ist ein Kosten- und kein Gesundheitssignal – die EFSA hält es bei Dosen weit über der realistischen Aufnahme für sicher.","benefits":"","interestingFact":"","research":""}},"e477":{"name":"Propylenglycolester","note":"Emulgator für Schlagcremes.","detail":{"risks":"Fettsäuren auf einem Propylenglycol-Gerüst, die Schlagcremes und Backmischungen lockern. Beide Hälften sind bei lebensmittelüblichen Dosen alltägliche Stoffwechselprodukte.","benefits":"","interestingFact":"","research":""}},"e479b":{"name":"Thermisch oxidiertes Sojaöl mit Mono- und Diglyceriden verestert","note":"Spritzschutz-Emulgator für Frittierfett.","detail":{"risks":"Sojaöl wird gezielt hitzebehandelt und verestert, damit Bratmargarine gleichmäßig bräunt, statt zu spritzen. Von der EFSA bei typischer Verwendung mit einer beruhigenden Sicherheitsspanne bewertet.","benefits":"","interestingFact":"","research":""}},"e481":{"name":"Natriumstearoyllactylat","note":"Back-Emulgator.","detail":{"risks":"Ein Hybrid aus Stearinsäure und Milchsäure, der die Glutenfilme stärkt – der Grund, warum geschnittenes Sandwichbrot beim Zusammendrücken wieder zurückfedert. Wird in alltägliches Fett und Lactat verdaut.","benefits":"","interestingFact":"","research":""}},"e482":{"name":"Calciumstearoyllactylat","note":"Back-Emulgator.","detail":{"risks":"Der Calcium-Zwilling von E481, der dieselbe teigverstärkende Aufgabe in Broten und Pfannkuchenmischungen erfüllt.","benefits":"","interestingFact":"","research":""}},"e491":{"name":"Sorbitanmonostearat","note":"Emulgator, bei typischen Dosierungen akzeptabel.","detail":{"risks":"Sorbit (ein Zuckeralkohol), gebunden an Stearinfett – Spitzname „synthetisches Wachs“. Es hilft Trockenhefe, gleichmäßig zu rehydratisieren, und hält Schlagcremes stabil; die EFSA bestätigte 2017 erneut einen beruhigenden Sicherheitsabstand.","benefits":"","interestingFact":"","research":""}},"e492":{"name":"Sorbitantristearat","note":"Mittel gegen Fettreif auf Schokolade.","detail":{"risks":"Ein Sorbitan-Emulgator, der den grauen „Fettreif“ auf Schokolade verlangsamt – diese Kakaobutterkristalle, die im Laufe der Zeit an die Oberfläche wandern. Gleiche Familie und Sicherheitsbewertung wie E491.","benefits":"","interestingFact":"","research":""}},"e493":{"name":"Sorbitanmonolaurat","note":"Emulgator.","detail":{"risks":"Das Laurinsäure-Mitglied der Sorbitan-Familie, verwendet in Toppings und Glasuren. Wird bei der Verdauung in Sorbit und Fett gespalten.","benefits":"","interestingFact":"","research":""}},"e495":{"name":"Sorbitanmonopalmitat","note":"Emulgator.","detail":{"risks":"Das Palmitinsäure-Sorbitan, meist eine Aufschlaghilfe. Gleiche Verdauungsgeschichte wie seine E49x-Geschwister.","benefits":"","interestingFact":"","research":""}},"e500":{"name":"Natriumcarbonate","note":"Natron.","detail":{"risks":"Natron und seine Verwandten – die Gasquelle in den meisten Backpulvern. Verleiht auch Laugengebäck und Ramen-Nudeln ihren typischen, alkalischen Biss.","benefits":"","interestingFact":"","research":""}},"e501":{"name":"Kaliumcarbonate","note":"Backtriebmittel.","detail":{"risks":"Natrons Kalium-Verwandter – historisch als „Pottasche“ bekannt, aus Holzasche ausgelaugt und das Triebmittel für Lebkuchen vor der Zeit des Backpulvers.","benefits":"","interestingFact":"","research":""}},"e503":{"name":"Ammoniumcarbonate","note":"Traditionelles Backtriebmittel.","detail":{"risks":"„Hirschhornsalz“, das Triebmittel alter europäischer Keksrezepte vor der Backpulver-Ära. Riecht im Ofen stechend nach Ammoniak, verflüchtigt sich beim Backen aber spurlos und hinterlässt extra knuspriges Gebäck.","benefits":"","interestingFact":"","research":""}},"e504":{"name":"Magnesiumcarbonate","note":"Trennmittel (auch Kletterkreide).","detail":{"risks":"Das weiße Pulver, mit dem Turnende und Kletternde ihre Hände einreiben; hält Speisesalz rieselfähig. Die Magensäure verwandelt es in ganz normales gelöstes Magnesium.","benefits":"","interestingFact":"","research":""}},"e507":{"name":"Salzsäure","note":"Prozesssäure, im Produkt neutralisiert.","detail":{"risks":"Klingt beunruhigend, aber Ihr Magen produziert täglich dieselbe Säure in höherer Konzentration. In der Lebensmittelverarbeitung wird sie neutralisiert, bevor das Produkt fertig ist.","benefits":"","interestingFact":"","research":""}},"e508":{"name":"Kaliumchlorid","note":"Mineralsalz als Kochsalzersatz.","detail":{"risks":"Der Standard-Ersatz für natriumarmes Salz – Kalium statt Natrium, mit einer leicht metallischen Note. Für die meisten Menschen ist das zusätzliche Kalium ein Plus.","benefits":"","interestingFact":"","research":""}},"e509":{"name":"Calciumchlorid","note":"Festigungsmittel (Gemüsekonserven, Käseherstellung).","detail":{"risks":"Ein Calciumsalz, das pflanzliche Pektine vernetzt und so Tomatenkonserven und Saure Gurken knackig hält. Käser geben es zur Milch, damit die Gallerte fest wird. Zudem die „Flüssigkeit“ in vielen Enteisern – auf die Konzentration kommt es an.","benefits":"","interestingFact":"","research":""}},"e511":{"name":"Magnesiumchlorid","note":"Festigungsmittel (auch Tofu-Gerinnungsmittel Nigari).","detail":{"risks":"Magnesium aus Meerwasser – als „Nigari“ das traditionelle japanische Tofu-Gerinnungsmittel, das Sojamilch stocken lässt. Eine Quelle für Magnesium in der Ernährung.","benefits":"","interestingFact":"","research":""}},"e513":{"name":"Schwefelsäure","note":"Prozesssäure, im Produkt neutralisiert.","detail":{"risks":"Wird nur während der Verarbeitung verwendet (z. B. zur Einstellung der Säure im Brauwasser) und vollständig zu Sulfatsalzen neutralisiert, bevor etwas ins Regal gelangt.","benefits":"","interestingFact":"","research":""}},"e514":{"name":"Natriumsulfate","note":"Säureregulator.","detail":{"risks":"Ein neutrales Mineralsalz – für Apotheker des 18. Jahrhunderts Glaubersalz, die es als Abführmittel verschrieben, was große Mengen auch heute noch sind.","benefits":"","interestingFact":"","research":""}},"e516":{"name":"Calciumsulfat","note":"Gips – Tofu-Gerinnungsmittel, Mehlbehandlungsmittel.","detail":{"risks":"Gips in Lebensmittelqualität (das gereinigte Gipskarton-Mineral). Es ist das klassische chinesische Gerinnungsmittel für Tofu und ein Hefenährstoff beim Backen, der ganz nebenbei verwertbares Calcium liefert.","benefits":"","interestingFact":"","research":""}},"e524":{"name":"Natriumhydroxid","note":"Natronlauge – Verarbeitungshilfsstoff, im Produkt vollständig ausreagiert.","detail":{"risks":"Ätzend in der Flasche, harmlos auf dem Teller: Laugengebäck erhält seine mahagonifarbene Kruste durch ein Laugenbad, und die Lauge wird beim Backen vollständig neutralisiert.","benefits":"","interestingFact":"","research":""}},"e526":{"name":"Calciumhydroxid","note":"Löschkalk, Verarbeitungshilfsstoff.","detail":{"risks":"Gelöschter Kalk – das „Cal“ der mexikanischen Nixtamalisation, das seit 3.500 Jahren Mais für Tortillas weich macht und dessen Niacin freisetzt. Im fertigen Lebensmittel vollständig ausreagiert.","benefits":"","interestingFact":"","research":""}},"e527":{"name":"Ammoniumhydroxid","note":"Verarbeitungsalkali.","detail":{"risks":"Ammoniaklösung zur Einstellung der Säure während der Verarbeitung (insbesondere bei Kakao). Sie reagiert ab oder verdampft; das verbleibende Ammonium geht in den normalen Stickstoffwechsel ein.","benefits":"","interestingFact":"","research":""}},"e529":{"name":"Calciumoxid","note":"Branntkalk, Verarbeitungshilfsstoff.","detail":{"risks":"Branntkalk – er löscht sich im Moment des Kontakts mit Feuchtigkeit zu Calciumhydroxid ab, erfüllt denselben Zweck wie E526 und endet als ganz normales Calcium.","benefits":"","interestingFact":"","research":""}},"e530":{"name":"Magnesiumoxid","note":"Trennmittel-Mineral.","detail":{"risks":"Dasselbe Magnesiumoxid, das als Nahrungsergänzungsmittel und Antazidum verkauft wird; hier hält es Kakaopulver rieselfähig.","benefits":"","interestingFact":"","research":""}},"e535":{"name":"Natriumferrocyanid","note":"Trennmittel in Salz.","detail":{"risks":"Trotz des furchterregenden Namens ist das Cyanid so fest an Eisen gebunden, dass es unresorbiert ausgeschieden wird – es hält Speisesalz auch bei feuchtem Wetter rieselfähig.","benefits":"","interestingFact":"","research":""}},"e536":{"name":"Kaliumferrocyanid","note":"Trennmittel in Salz.","detail":{"risks":"Die Kaliumform von E535 mit derselben eisengebundenen Chemie: Die Cyanidgruppe kann im Körper nicht freigesetzt werden, und die EFSA hat die Sicherheit 2018 erneut bestätigt.","benefits":"","interestingFact":"","research":""}},"e538":{"name":"Calciumferrocyanid","note":"Trennmittel in Salz.","detail":{"risks":"Das seltenste der drei Ferrocyanid-Trennsalze mit identischer fest gebundener Chemie und derselben Neubewertung durch die EFSA.","benefits":"","interestingFact":"","research":""}},"e541":{"name":"Natriumaluminiumphosphat","note":"Aluminiumhaltiges Backtriebmittel.","detail":{"risks":"Eine langsam wirkende Backsäure, deren Aluminium zur Gesamtexposition über die Nahrung beiträgt – die EFSA hat die Regeln für Aluminiumzusätze 2012 verschärft, und der Stoff ist weitgehend aus EU-Rezepturen verschwunden.","benefits":"","interestingFact":"","research":""}},"e551":{"name":"Siliciumdioxid","note":"Trennmittel; Nanopartikel-Anteil wird in der EU überprüft.","detail":{"risks":"Gereinigter Sand in so feiner Pulverform, dass er Partikel umhüllt und Gewürzmischungen sowie Tütensuppen rieselfähig hält. Chemisch träge; die offene Frage, der die EFSA nachgeht, ist, ob sich der Anteil in Nanogröße anreichern kann.","benefits":"","interestingFact":"","research":""}},"e552":{"name":"Calciumsilikat","note":"Trennmittel-Mineral.","detail":{"risks":"Ein Kalk-Kieselsäure-Mineral, das ein Vielfaches seines Eigengewichts an Feuchtigkeit aufsaugt und Pulver locker hält. Wird praktisch nicht aufgenommen.","benefits":"","interestingFact":"","research":""}},"e553b":{"name":"Talkum","note":"Trennmittel-Mineral (lebensmittelecht, asbestfrei).","detail":{"risks":"Das weichste Mineral der Erde; poliert Reiskörner und bestäubt Kaugummi. Lebensmittelqualität ist garantiert asbestfrei; es wird unverdaut ausgeschieden.","benefits":"","interestingFact":"","research":""}},"e554":{"name":"Natriumaluminiumsilicat","note":"Aluminiumhaltiges Trennmittel.","detail":{"risks":"Ein Trennmittel-Ton, dessen Aluminiumgehalt zum strengen wöchentlichen EFSA-Grenzwert für Aluminium zählt – der Grund, warum EU-Regulierungsbehörden diese Gruppe 2014 gestrichen haben.","benefits":"","interestingFact":"","research":""}},"e555":{"name":"Kaliumaluminiumsilicat","note":"Aluminiumhaltiger Trägerstoff (Perglanzfarben).","detail":{"risks":"Natürlicher Glimmer – der Schimmer auf perlmuttartigen Kuchendekorationen. Wegen desselben Aluminium-Anreicherungsrisikos wie seine Verwandten beanstandet.","benefits":"","interestingFact":"","research":""}},"e558":{"name":"Bentonit","note":"Tonmineral zur Klärung von Wein und Saft.","detail":{"risks":"Ein vulkanisches Tonmineral, das in Wasser quillt und trübungsbildende Proteine bindet – der meiste Weißwein, den Sie getrunken haben, wurde damit geklärt und danach herausgefiltert.","benefits":"","interestingFact":"","research":""}},"e559":{"name":"Kaolin","note":"Tonmineral-Trennmittel.","detail":{"risks":"Porzellanerde – das Porzellanmineral – gelegentlich als Trennmittel verwendet. Träge und unresorbiert.","benefits":"","interestingFact":"","research":""}},"e570":{"name":"Fettsäuren","note":"Speisefettsäuren.","detail":{"risks":"Stearinsäure und Co. – dieselben Fettsäuren, die Ihr Körper aus jedem Fett aufnimmt, verwendet als Überzugs- und Trennmittel.","benefits":"","interestingFact":"","research":""}},"e575":{"name":"Glucono-delta-Lacton","note":"Langsam freisetzende Säure (Tofu, Pökelwaren).","detail":{"risks":"Ein oxidierter Zucker, der in Wasser langsam sauer wird – perfekt für Seidentofu, bei dem der allmähliche pH-Abfall die Sojamilch zu einem glatten Gel gerinnen lässt.","benefits":"","interestingFact":"","research":""}},"e576":{"name":"Natriumgluconat","note":"Mineralsalz der Gluconsäure.","detail":{"risks":"Oxidierte und an Natrium gebundene Glucose – ein Mineralstoffträger und Stabilisator, der wie Zucker verstoffwechselt wird.","benefits":"","interestingFact":"","research":""}},"e577":{"name":"Kaliumgluconat","note":"Mineralsalz der Gluconsäure.","detail":{"risks":"Die Kaliumform von Gluconat, sanft genug, dass Apotheken sie als Kaliumpräparat verkaufen.","benefits":"","interestingFact":"","research":""}},"e578":{"name":"Calciumgluconat","note":"Calciumsalz, Festigungsmittel.","detail":{"risks":"Calcium an einem Zuckersäure-Träger – dieselbe Verbindung, die Krankenhäuser bei Calciummangel intravenös verabreichen. In Lebensmitteln festigt es Obst und Gemüse.","benefits":"","interestingFact":"","research":""}},"e579":{"name":"Eisen(II)-gluconat","note":"Eisensalz – schwärzt Oliven.","detail":{"risks":"Ein Eisenpräparat im Farbeinsatz: „Schwarze“ Oliven in Dose oder Glas sind meist grüne Oliven, die schwarz oxidiert und mit diesem Eisensalz fixiert wurden.","benefits":"","interestingFact":"","research":""}},"e585":{"name":"Eisen(II)-lactat","note":"Eisensalz, Olivenschwärzer.","detail":{"risks":"Eisen, gebunden an Lactat; erfüllt denselben Zweck beim Schwärzen von Oliven wie E579 und wird zur Anreicherung von Lebensmitteln mit Eisen verwendet.","benefits":"","interestingFact":"","research":""}},"e586":{"name":"4-Hexylresorcin","note":"Anti-Browning-Mittel für Garnelen.","detail":{"risks":"Verhindert, dass Garnelenpanzer nach dem Fang schwarze Flecken entwickeln, indem es dasselbe Enzym blockiert, das aufgeschnittene Äpfel braun werden lässt. Auch als Antiseptikum in Halstabletten im Einsatz.","benefits":"","interestingFact":"","research":""}},"e620":{"name":"Glutaminsäure","note":"Umami-Verstärker; Empfindlichkeitsreaktionen bei einigen Personen.","detail":{"risks":"Die freie Form der häufigsten Aminosäure in Ihrer Ernährung – Parmesan besteht zu 1,2% aus reinem Glutamat. Als Zusatzstoff konzentriert es Umami; die Diskussionen über Empfindlichkeit und Überessen spiegeln die von MSG (E621) wider.","benefits":"","interestingFact":"","research":""}},"e621":{"name":"Mononatriumglutamat","note":"Geschmacksverstärker; Empfindlichkeitsreaktionen bei einigen Personen.","detail":{"risks":"Die reine Form von Umami, 1908 aus Kombu-Algenbrühe isoliert. Glutamat selbst steckt in Parmesan, Tomaten und Muttermilch; die Panik um das „China-Restaurant-Syndrom“ von 1968 hielt kontrollierten Tests weitgehend nicht stand, obwohl eine Minderheit auf große Dosen reagiert. Die EFSA legte 2017 eine offizielle Aufnahmegrenze fest – die vor allem durch snackintensive Ernährung überschritten wird. Sein eigentliches ernährungsbezogenes Problem: Es verleitet sehr leicht zum Überessen von hochverarbeiteten Lebensmitteln.","benefits":"","interestingFact":"","research":""}},"e622":{"name":"Monokaliumglutamat","note":"Glutamat-Geschmacksverstärker.","detail":{"risks":"MSG, bei dem Kalium das Natrium ersetzt, verwendet in natriumarmen Rezepten. Identischer Umami-Mechanismus und dieselbe EFSA-Glutamat-Aufnahmegrenze.","benefits":"","interestingFact":"","research":""}},"e627":{"name":"Dinatriumguanylat","note":"Geschmacksverstärker, oft mit MSG kombiniert.","detail":{"risks":"Ein Nukleotid, das Umami vervielfacht – kombiniert mit MSG schmeckt es bis zu 30× intensiver als allein, weshalb sie auf Zutatenlisten oft zusammen auftauchen. Gewonnen aus Hefe oder Fisch; Menschen mit Gicht wird geraten, purinreiche Zusatzstoffe wie diesen zu begrenzen.","benefits":"","interestingFact":"","research":""}},"e628":{"name":"Dikaliumguanylat","note":"Nukleotid-Geschmacksverstärker.","detail":{"risks":"Die Kaliumform von Guanylat (E627), die Umami in natriumarmen Produkten verstärkt. Gleiche Herkunft aus Hefe und derselbe Purin-Hinweis für Gichtgefährdete.","benefits":"","interestingFact":"","research":""}},"e631":{"name":"Dinatriuminosinat","note":"Geschmacksverstärker, oft mit MSG kombiniert.","detail":{"risks":"Das Umami-Nukleotid aus getrockneten Bonitoflocken (der Basis der japanischen Dashi-Brühe), heute durch Fermentation hergestellt. Dieselbe MSG-Synergie und dieselben Purin-Hinweise wie bei E627.","benefits":"","interestingFact":"","research":""}},"e635":{"name":"Dinatrium-5'-ribonucleotid","note":"E627 + E631 kombiniert; Umami-Booster.","detail":{"risks":"Eine 50/50-Mischung aus Guanylat und Inosinat – eine Zeile auf dem Etikett, die beide Umami-Nukleotide liefert. Sein Vorhandensein deutet fast immer auf MSG (oder einen glutamatreichen Extrakt) in der Nähe hin, da es allein kaum wirkt.","benefits":"","interestingFact":"","research":""}},"e640":{"name":"Glycin","note":"Die einfachste Aminosäure, leichte Süße.","detail":{"risks":"Die kleinste Aminosäure – ein Drittel des Proteins Kollagen ist Glycin. Als Zusatzstoff rundet es bittere Noten ab und verleiht eine dezente Süße.","benefits":"","interestingFact":"","research":""}},"e650":{"name":"Zinkacetat","note":"Zinksalz (Kaugummi).","detail":{"risks":"An Essigsäure gebundenes Zink, meist in „atemfrischendem“ Kaugummi, wo Zink Schwefelverbindungen neutralisiert. Dasselbe Salz wird auch in Erkältungstabletten verwendet.","benefits":"","interestingFact":"","research":""}},"e900":{"name":"Dimethylpolysiloxan","note":"Silikon-Antischaummittel (Frittieröl).","detail":{"risks":"Ein lebensmittelechtes Silikon, das verhindert, dass Frittieröl überschäumt – der Grund, warum Fritteusen im Fast Food nicht überkochen. Völlig inert und unresorbiert; außerdem der Hauptbestandteil von Silly Putty.","benefits":"","interestingFact":"","research":""}},"e901":{"name":"Bienenwachs","note":"Natürliches Überzugswachs.","detail":{"risks":"Dasselbe Wachs, aus dem Bienen Waben bauen, für Glanz auf Fruchtgummis und Zitrusfrüchte poliert. Unverdaulich – es wandert einfach durch.","benefits":"","interestingFact":"","research":""}},"e902":{"name":"Candelillawachs","note":"Pflanzliches Überzugswachs.","detail":{"risks":"Wachs, das von einem mexikanischen Wüstenstrauch geschabt wird, der sich damit gegen Trockenheit schützt – und jetzt stattdessen Ihre Gummibärchen überzieht. Unverdaulich und inert.","benefits":"","interestingFact":"","research":""}},"e903":{"name":"Carnaubawachs","note":"Palmenblatt-Überzugswachs.","detail":{"risks":"Gewonnen aus brasilianischen Palmenblättern – das härteste bekannte Naturwachs, das sowohl M&M’s als auch Sportwagen zum Glänzen bringt.","benefits":"","interestingFact":"","research":""}},"e904":{"name":"Schellack","note":"Insektenharz-Überzug.","detail":{"risks":"Von der Lackschildlaus auf thailändischen und indischen Bäumen abgesondert und dann gereinigt – der glänzende Überzug auf Schokolinsen und Äpfeln sowie dasselbe Harz wie in möbelpolierter Handwerkskunst. Nicht vegetarisch.","benefits":"","interestingFact":"","research":""}},"e905":{"name":"Mikrokristallines Wachs","note":"Überzugswachs aus Erdöl.","detail":{"risks":"Ein hochraffiniertes Erdölwachs zum Überziehen von Kaugummi und Süßwaren. Zu groß, um aufgenommen zu werden, passiert es den Körper einfach – das einzige Anliegen der EFSA ist die Reinheitskontrolle.","benefits":"","interestingFact":"","research":""}},"e914":{"name":"Oxidiertes Polyethylenwachs","note":"Synthetisches Wachs für Zitrusfrüchte.","detail":{"risks":"Ein synthetisches Wachs, das auf Zitrusfruchtschalen gesprüht wird, um den Feuchtigkeitsverlust auf dem Weg von der Plantage ins Regal zu verlangsamen. Bleibt auf der Schale; Früchte vor dem Abreiben der Schale waschen.","benefits":"","interestingFact":"","research":""}},"e920":{"name":"L-Cystein","note":"Mehlbehandlungsmittel aus Fermentation.","detail":{"risks":"Eine Aminosäure, die das Gluten entspannt, damit industrielle Teigmaschinen ihn schnell dehnen können. Historisch aus Federn und menschlichem Haar gewonnen (in der EU seit 2001 verbotene Quellen – heute wird es aus Zucker fermentiert), eine Tatsache, die seinem Ruf eine schillernde Note verleiht.","benefits":"","interestingFact":"","research":""}},"e927b":{"name":"Carbamid","note":"Texturgeber für Kaugummi.","detail":{"risks":"Harnstoff – ein Molekül, das Ihr Körper beim Proteinstoffwechsel ständig produziert – macht zuckerfreien Kaugummi weich. In den beteiligten Milligrammdosen völlig unbedeutend.","benefits":"","interestingFact":"","research":""}},"e938":{"name":"Argon","note":"Inertes Verpackungsgas.","detail":{"risks":"Ein Edelgas aus der Luft (1% jedes Atemzugs), das mit nichts reagiert – in Verpackungen gespült, um Sauerstoff zu verdrängen.","benefits":"","interestingFact":"","research":""}},"e939":{"name":"Helium","note":"Inertes Verpackungsgas.","detail":{"risks":"Das Ballongas, völlig inert, wird gelegentlich zum Schutz von Lebensmitteln in Verpackungen verwendet. Es entweicht in dem Moment, in dem Sie die Packung öffnen.","benefits":"","interestingFact":"","research":""}},"e941":{"name":"Stickstoff","note":"Verpackungsgas – 78% der Luft, die Sie atmen.","detail":{"risks":"Das Gas, das den „leeren“ Raum in Tüten voller Chips füllt, ist keine Mogelpackung – es ist Stickstoff, der die Chips vor Sauerstoff und Zerquetschen schützt. Macht außerdem Nitro-Kaffee cremig.","benefits":"","interestingFact":"","research":""}},"e942":{"name":"Lachgas","note":"Treibgas für Schlagsahne (Lachgas).","detail":{"risks":"Das Treibgas in Kapseln für Schlagsahne. Es löst sich unter Druck in der Sahne und dehnt sie beim Austreten um das Achtfache aus – die Spur, die Sie aufnehmen, ist in Minuten verschwunden.","benefits":"","interestingFact":"","research":""}},"e948":{"name":"Sauerstoff","note":"Verpackungsgas.","detail":{"risks":"Ganz normaler Sauerstoff, der manchmal Packungen mit rohem Fleisch zugesetzt wird, um die Oberfläche leuchtend rot zu halten. Sie atmen mit jedem Atemzug weit mehr davon ein.","benefits":"","interestingFact":"","research":""}},"e949":{"name":"Wasserstoff","note":"Verpackungsgas.","detail":{"risks":"Das leichteste Gas, das selten als Schutzgasverpackung verwendet wird. Inert im Lebensmittel und längst verflogen, wenn Sie essen.","benefits":"","interestingFact":"","research":""}},"e999":{"name":"Quillaia-Extrakt","note":"Schaummittel aus Seifenrinde (Root-Beer-Schaum).","detail":{"risks":"Extrakt des chilenischen Seifenrindenbaums, dessen natürliche Saponine die Schaumkrone von Root Beer erzeugen. Derselbe Extrakt wird als Impfstoff-Adjuvans verwendet – in Lebensmitteldosen sorgt er einfach für Bläschen.","benefits":"","interestingFact":"","research":""}},"e950":{"name":"Acesulfam K","note":"Künstlicher Süßstoff; Langzeitwirkungen umstritten.","detail":{"risks":"200× süßer als Zucker, null Kalorien, wird überhaupt nicht verstoffwechselt – verlässt den Körper innerhalb von 24 Stunden unverändert. Langzeit-Epidemiologie (einschließlich der Empfehlung der WHO von 2023 gegen Süßstoffe zur Gewichtskontrolle) hält die Debatte offen.","benefits":"","interestingFact":"","research":""}},"e951":{"name":"Aspartam","note":"IARC Klasse 2B (möglichweise krebserregend, 2023); Aufnahmegrenzen gelten.","detail":{"risks":"Zwei miteinander verbundene Aminosäuren, 200× süßer als Zucker. Im Jahr 2023 stufte die IARC es als „möglicherweise krebserregend“ ein (dieselbe Kategorie 2B wie Aloe Vera und eingelegtes Gemüse), während der Sachverständigenausschuss für Lebensmittelzusatzstoffe der WHO seine Aufnahmegrenze beibehielt – etwa 12 Dosen Diät-Limonade pro Tag für einen Erwachsenen. Menschen mit der Genkrankheit PKU müssen es vollständig meiden; dafür gibt es den Warnhinweis „enthält eine Phenylalaninquelle“.","benefits":"","interestingFact":"","research":""}},"e952":{"name":"Cyclamat","note":"Süßstoff in den USA verboten, begrenzte Dosen in der EU.","detail":{"risks":"1937 von einem Studenten entdeckt, der seine Zigarette auf Laborpulver legte und Süße schmeckte. In den USA seit 1970 wegen (später umstrittener) Ratten-Tumor-Befunde verboten; die EU erlaubt es mit strengen Grenzen.","benefits":"","interestingFact":"","research":""}},"e953":{"name":"Isomalt","note":"Polyol; abführend bei hohen Dosen.","detail":{"risks":"Der Favorit der Zuckerkünstler – es schmilzt glasklar ohne zu karamellisieren, weshalb Schaustücke in TV-Backshows meistens aus Isomalt bestehen. Es gelten die üblichen Verdauungshinweise für Polyole.","benefits":"","interestingFact":"","research":""}},"e954":{"name":"Saccharin","note":"Künstlicher Süßstoff mit bewegter Geschichte.","detail":{"risks":"Der älteste künstliche Süßstoff (1879, entdeckt von einem Chemiker, der sich vor dem Abendessen nicht die Hände gewaschen hatte). Trug 20 Jahre lang einen Krebs-Warnhinweis in den USA, bis gezeigt wurde, dass der Ratten-Blasen-Mechanismus nicht auf Menschen zutrifft – 2000 von der Liste gestrichen, aber sein langer Schatten bleibt.","benefits":"","interestingFact":"","research":""}},"e955":{"name":"Sucralose","note":"Künstlicher Süßstoff; Debatten über Erhitzen und Mikrobiom.","detail":{"risks":"Zucker mit drei ausgetauschten Chloratomen – 600× süßer und weitgehend unresorbiert. Aktuelle Debatten: Bei hohen Backtemperaturen kann es sich in bedenkliche Verbindungen zersetzen, und Studien sind sich uneinig über Auswirkungen auf das Darm-Mikrobiom.","benefits":"","interestingFact":"","research":""}},"e957":{"name":"Thaumatin","note":"Süßes Protein aus einer afrikanischen Frucht.","detail":{"risks":"Ein Protein aus der Westafrikanischen Katamfe-Frucht – die süßeste bekannte natürliche Substanz, bezogen aufs Gewicht etwa 2.000× süßer als Zucker. Wird wie jedes andere Protein verdaut.","benefits":"","interestingFact":"","research":""}},"e959":{"name":"Neohesperidin DC","note":"Aus Zitrusfrüchten gewonnener Süßstoff.","detail":{"risks":"Hergestellt aus Verbindungen der Bitterorangenschale, 1.500× süßer als Zucker mit mentholartigem Nachgeschmack; wird auch verwendet, um Bitterkeit in Medizin zu überdecken.","benefits":"","interestingFact":"","research":""}},"e960":{"name":"Steviolglycoside","note":"Aus Stevia gewonnener Süßstoff.","detail":{"risks":"Aus Steviablättern extrahiert, von den Guaraní in Paraguay seit Jahrhunderten verwendet. 250–300× süßer als Zucker bei null Kalorien; Ihre Darmbakterien bauen es ab und es wird ausgeschieden. Der leichte Lakritz-Nachgeschmack ist der Kompromiss.","benefits":"","interestingFact":"","research":""}},"e961":{"name":"Neotam","note":"Aspartam-Derivat, 8000× süßer als Zucker.","detail":{"risks":"Aspartam, so modifiziert, dass es etwa 40× stärkere Süßkraft besitzt und beim Backen stabil bleibt. Die Dosierungen sind mikroskopisch klein, und anders als bei Aspartam wird so wenig Phenylalanin freigesetzt, dass kein PKU-Warnhinweis nötig ist; Langzeitdaten sind allerdings spärlicher.","benefits":"","interestingFact":"","research":""}},"e962":{"name":"Aspartam-Acesulfam-Salz","note":"Kombinationssüßstoff; siehe Anmerkungen zu Aspartam.","detail":{"risks":"Aspartam und Acesulfam K, zusammen zu einem einzigen Molekül kristallisiert, das im Mund wieder in beide Stoffe zerfällt – alle Erwägungen zu beiden Komponenten treffen zu, einschließlich des PKU-Warnhinweises.","benefits":"","interestingFact":"","research":""}},"e965":{"name":"Maltit","note":"Polyol; wirkt in hohen Dosen abführend.","detail":{"risks":"Der bevorzugte Zuckerersatz in Schokolade „ohne Zuckerzusatz“ – zu 90 % so süß wie Zucker bei halber Kalorienzahl. Aber auch das berüchtigtste Polyol für Verdauungsbeschwerden ab etwa 20 g, daher die Warnhinweise auf zuckerfreien Süßwaren.","benefits":"","interestingFact":"","research":""}},"e966":{"name":"Lactit","note":"Aus Milch gewonnener Zuckeraustauschstoff (Polyol); wirkt in hohen Dosen abführend.","detail":{"risks":"Ein aus Milchzucker hergestellter Zuckeralkohol, mild süß und hauptsächlich von Darmbakterien fermentiert – in pharmazeutischen Dosierungen wird genau dieses Molekül sprichwörtlich als Abführmittel verkauft.","benefits":"","interestingFact":"","research":""}},"e967":{"name":"Xylit","note":"Polyol; wirkt in hohen Dosen abführend.","detail":{"risks":"Zuckeralkohol aus Birkensaft/Birkenrinde, den Mundbakterien nicht fermentieren können – das Kauen von Xylit-Kaugummi reduziert nachweisbar Karies, ein seltener Zusatzstoff mit belegtem Nutzen. Zwei Vorsichtsmaßnahmen: wirkt ab etwa 30 g abführend und ist für Hunde extrem giftig.","benefits":"","interestingFact":"","research":""}},"e968":{"name":"Erythrit","note":"Polyol; Studie von 2023 löste Debatte über Herz-Kreislauf-Risiken aus.","detail":{"risks":"Das verträglichste Polyol – 90 % werden aufgenommen, bevor sie den Dickdarm erreichen, daher nahezu keine Verdauungsauswirkungen und null Kalorien. Eine Studie in Nature Medicine von 2023 brachte hohe Erythrit-Spiegel im Blut mit einem Gerinnungsrisiko in Verbindung; ob Erythrit aus der Nahrung dies verursacht, wird derzeit aktiv erforscht.","benefits":"","interestingFact":"","research":""}},"e1103":{"name":"Invertase","note":"Enzym, das den Kern von Süßwaren verflüssigt.","detail":{"risks":"Das Enzym (aus Hefe), das festen Fondant im Laufe von Wochen verflüssigt – so erhalten Kirschpralinen ihren flüssigen Kern, nachdem sie mit fester Masse gefüllt wurden.","benefits":"","interestingFact":"","research":""}},"e1105":{"name":"Lysozym","note":"Enzymatisch wirkendes Konservierungsmittel aus Hühnereieiweiß (Käse, Wein).","detail":{"risks":"Ein antibakterielles Enzym aus Eiklar – dasselbe, das auch in Tränen und Speichel vorkommt. Personen mit Eiallergie sollten wissen, dass es sich in manchen Hartkäsen und Weinen verbirgt.","benefits":"","interestingFact":"","research":""}},"e1200":{"name":"Polydextrose","note":"Synthetischer löslicher Ballaststoff.","detail":{"risks":"Glukose, die so verknüpft ist, dass körpereigene Enzyme sie nicht spalten können; sie verhält sich daher wie ein löslicher Ballaststoff – verleiht „Light“-Lebensmitteln Volumen mit nur 1 kcal/g statt der 4 kcal/g von Zucker.","benefits":"","interestingFact":"","research":""}},"e1201":{"name":"Polyvinylpyrrolidon","note":"Klärhilfsmittel und Tablettenbindemittel.","detail":{"risks":"Ein Polymer, das Polyphenole bindet, die Bier und Saft trüben würden, und dann zusammen mit ihnen herausgefiltert wird. Eventuell verbleibende Spuren werden unresorbiert ausgeschieden.","benefits":"","interestingFact":"","research":""}},"e1400":{"name":"Dextrine","note":"Verdickungsmittel aus gerösteter Stärke.","detail":{"risks":"Stärke, die durch Rösten leicht aufgeschlossen wurde – dieselbe Chemie, die die Kruste eines Baguettes bräunt. Wird genau wie normale Stärke verdaut.","benefits":"","interestingFact":"","research":""}},"e1404":{"name":"Oxidierte Stärke","note":"Modifizierte Stärke; wird wie Stärke verdaut.","detail":{"risks":"Stärke, die so behandelt wurde, dass sie bei geringerer Viskosität für Cremes und Teige eindickt. „Modifiziert“ bedeutet physikalisch/chemisch verändert – nicht gentechnisch verändert – und sie wird wie gewöhnliche Stärke verdaut.","benefits":"","interestingFact":"","research":""}},"e1410":{"name":"Monostärkephosphat","note":"Modifizierte Stärke; wird wie Stärke verdaut.","detail":{"risks":"Stärke mit Phosphatverankerungen, die Hitzebeständigkeit und Säuretoleranz bieten, sodass Saucen in Konserven dickflüssig bleiben. Wird wie Stärke verdaut.","benefits":"","interestingFact":"","research":""}},"e1412":{"name":"Distärkephosphat","note":"Modifizierte Stärke; wird wie Stärke verdaut.","detail":{"risks":"Stärke, die mit Phosphatbrücken vernetzt ist, um Rühren und Hitze standzuhalten – das Rückgrat von Instant-Puddings. Wird wie Stärke verdaut.","benefits":"","interestingFact":"","research":""}},"e1414":{"name":"Acetyliertes Distärkephosphat","note":"Modifizierte Stärke; wird wie Stärke verdaut.","detail":{"risks":"Vernetzte Stärke mit zusätzlichen Acetylgruppen für Gefrier-Tau-Stabilität – der Grund, warum gefrorene Fertiggerichte beim Wiedererwärmen kein Wasser ausscheiden. Wird wie Stärke verdaut.","benefits":"","interestingFact":"","research":""}},"e1420":{"name":"Acetylierte Stärke","note":"Modifizierte Stärke; wird wie Stärke verdaut.","detail":{"risks":"Stärke mit aus Essigsäure stammenden Acetylgruppen, die der Retrogradation (dem Altbackenwerden) entgegenwirken. Wird wie Stärke verdaut.","benefits":"","interestingFact":"","research":""}},"e1422":{"name":"Acetyliertes Distärkeadipat","note":"Modifizierte Stärke; wird wie Stärke verdaut.","detail":{"risks":"„Modifizierte Stärke“ bedeutet nicht gentechnisch verändert – es handelt sich um Mais- oder Kartoffelstärke, die chemisch angepasst wurde, damit Saucen das Einfrieren und Wiedererwärmen überstehen, ohne wässrig zu werden. Der Körper verdaut sie wie normale Stärke.","benefits":"","interestingFact":"","research":""}},"e1440":{"name":"Hydroxypropylstärke","note":"Modifizierte Stärke, im Allgemeinen gut verträglich.","detail":{"risks":"Stärke mit wasserliebenden Seitengruppen für ein geschmeidiges Verdicken bei niedrigen Temperaturen. Wird weitgehend als Stärke verdaut; der modifizierte Anteil verhält sich wie Ballaststoff.","benefits":"","interestingFact":"","research":""}},"e1442":{"name":"Hydroxypropyldistärkephosphat","note":"Modifizierte Stärke, im Allgemeinen gut verträglich.","detail":{"risks":"Die robusteste unter den modifizierten Stärken – vernetzt und substituiert, behält ihre verdickende Wirkung beim Einkochen, Einfrieren und Wiedererwärmen gleichermaßen. Wird größtenteils als Stärke verdaut.","benefits":"","interestingFact":"","research":""}},"e1450":{"name":"Stärkenatriumoctenylsuccinat","note":"Emulgator auf Stärkebasis (auch in Vitaminpräparaten).","detail":{"risks":"Stärke mit einem fettliebenden Rest versehen, damit sie emulgieren kann – der Trägerstoff, der pulverförmige Aromen und Vitamine in Säuglingsnahrung gleichmäßig verteilt hält.","benefits":"","interestingFact":"","research":""}},"e1451":{"name":"Acetylierte oxidierte Stärke","note":"Modifizierte Stärke; wird wie Stärke verdaut.","detail":{"risks":"Eine zweifach behandelte Stärke, die die Klarheit der Oxidation mit der Stabilität der Acetylierung kombiniert. Verdauungstechnisch dennoch einfach Stärke.","benefits":"","interestingFact":"","research":""}},"e1505":{"name":"Triethylcitrat","note":"Aromaträger und Schaumstabilisator auf Citratbasis.","detail":{"risks":"Zitronensäure mit drei Ethanolgruppen – sie stabilisiert geschlagenes Eiweiß in flüssigem Vollei aus der Packung und dient als Aromaträger. Wird bei der Verdauung wieder in Citrat und Spuren von Alkohol gespalten.","benefits":"","interestingFact":"","research":""}},"e1518":{"name":"Triacetin","note":"Aromaträger auf Glycerinbasis.","detail":{"risks":"Glycerin mit drei Essigsäuregruppen, das Aromen in Kaugummi und Süßwaren löst. Wird zu Glycerin und Acetat verdaut, beides alltägliche Stoffwechselprodukte.","benefits":"","interestingFact":"","research":""}},"e1520":{"name":"Propylenglycol","note":"Aromaträger; in Lebensmitteln sicher.","detail":{"risks":"Das Lösungsmittel, das die meisten flüssigen Lebensmittelaromen trägt. Wird zu Milchsäure verstoffwechselt; der Grenzwert der EFSA ist im Vergleich zur Belastung durch Lebensmittel großzügig bemessen. Seine schlechte Presse rührt meist daher, dass es auch in E-Zigaretten und Frostschutzmitteln verwendet wird – in Lebensmitteldosierungen ist es völlig unbedenklich.","benefits":"","interestingFact":"","research":""}}}`),n={methylparaben:{note:`Kurzkettiges Paraben; der SCCS stuft es bei ≤0,4% als sicher ein, es ist jedoch ein dokumentierter schwacher hormoneller Nachahmer.`},ethylparaben:{note:`Kurzkettiges Paraben; in der EU mit Konzentrationsgrenzen zugelassen.`},propylparaben:{note:`Längerkettiges Paraben mit stärkeren Hinweisen auf hormonelle Wirksamkeit; in der EU konzentrationsbeschränkt.`},butylparaben:{note:`Längerkettiges Paraben mit den stärksten Hinweisen auf hormonelle Wirksamkeit; in der EU beschränkt.`},isobutylparaben:{note:`In EU-Kosmetika seit 2014 verboten.`},paraben:{note:`Konservierungsmittel aus der Paraben-Familie; Debatte über hormonelle Wirksamkeit variiert je nach Kettenlänge.`},formaldehyde:{note:`IARC-Gruppe-1-Karzinogen; in EU-Kosmetika verboten/stark eingeschränkt.`},"dmdm hydantoin":{note:`Spaltet langsam Formaldehyd ab; Bedenken hinsichtlich Sensibilisierung.`},"imidazolidinyl urea":{note:`Formaldehydabspalter; häufiger Auslöser von Kontaktallergien.`},"diazolidinyl urea":{note:`Formaldehydabspalter; häufiger Auslöser von Kontaktallergien.`},"quaternium-15":{note:`Starker Formaldehydabspalter; in EU-Kosmetika seit 2022 verboten.`},"2-bromo-2-nitropropane-1,3-diol":{note:`Formaldehydabspalter; kann mit Aminen Nitrosamine bilden.`},methylisothiazolinone:{note:`Bedeutendes Kontaktallergen; in EU-Leave-on-Produkten verboten.`},methylchloroisothiazolinone:{note:`Starkes Sensibilisierungsmittel; in der EU nur in Rinse-off-Produkten unter strengen Grenzwerten erlaubt.`},triclosan:{note:`Bedenken hinsichtlich hormoneller Wirksamkeit und Antibiotikaresistenzen; in der EU beschränkt.`},phenoxyethanol:{note:`Weit verbreitet; der SCCS stuft es bei ≤1% als sicher ein. Leichtes Reizpotenzial.`},chlorphenesin:{note:`Konservierungsmittel, gelegentlicher Reizstoff.`},"benzyl alcohol":{note:`Konservierungsmittel und deklarationspflichtiges Duftstoffallergen.`},"sodium benzoate":{note:`Mildes, gut verträgliches Konservierungsmittel in kosmetischen Dosierungen.`},"potassium sorbate":{note:`Mildes, gut verträgliches Konservierungsmittel.`},"sodium lauryl sulfate":{note:`Effektiver Reiniger; entzieht natürliche Öle und reizt empfindliche Haut/Kopfhaut.`},"ammonium lauryl sulfate":{note:`Tensid der SLS-Klasse; ähnliches Reizprofil.`},"sodium laureth sulfate":{note:`Milder als SLS; Spuren von 1,4-Dioxan aus der Herstellung möglich.`},"cocamidopropyl betaine":{note:`Mildes Tensid; verunreinigungsbedingte Allergien kommen vor.`},"cocamide dea":{note:`IARC 2B (möglicherweise krebserregend); in EU-Kosmetika verboten.`},"cocamide mea":{note:`Nitrosaminbildung mit bestimmten Konservierungsmitteln möglich.`},triethanolamine:{note:`pH-Wert-Regulator; Bedenken hinsichtlich der Nitrosaminbildung in einigen Rezepturen.`},"benzophenone-3":{note:`Hinweise auf hormonelle Wirksamkeit; die EU hat die zulässige Konzentration 2022 gesenkt. Zudem riffschädigend.`},oxybenzone:{note:`Hinweise auf hormonelle Wirksamkeit; in der EU beschränkt. Zudem riffschädigend.`},"ethylhexyl methoxycinnamate":{note:`Östrogene Wirkung in Studien; wird schrittweise reduziert.`},octocrylene:{note:`Kann zu Benzophenon abbauen; Berichte über Fotoallergien.`},homosalate:{note:`SCCS senkte die sichere Konzentration aufgrund von Fragen zur hormonellen Wirksamkeit.`},"butyl methoxydibenzoylmethane":{note:`Weit verbreiteter UVA-Filter; Fotostabilität ist das Hauptproblem.`},"titanium dioxide":{note:`Sicher auf der Haut; einatembare Sprayformen (Nano) vermeiden.`},"zinc oxide":{note:`Mineralischer UV-Filter, gut verträglich.`},"polyethylene terephthalate":{note:`Festes synthetisches Polymer – bewusst zugesetztes Mikroplastik.`},polyethylene:{note:`Klassisches Mikroperlen-Polymer; EU-Beschränkung wird schrittweise eingeführt.`},polypropylene:{note:`Festes synthetisches Polymer – bewusst zugesetztes Mikroplastik.`},"polymethyl methacrylate":{note:`Acryl-Mikroplastik, das für die Textur verwendet wird.`},"nylon-12":{note:`Polyamid-Mikroplastikpulver.`},"nylon-6":{note:`Polyamid-Mikroplastikpulver.`},"acrylates copolymer":{note:`Filmbildendes Polymer; gilt in fester Form als Mikroplastik.`},"acrylates crosspolymer":{note:`Filmbildendes Polymer; gilt in fester Form als Mikroplastik.`},cyclopentasiloxane:{note:`In der EU in Rinse-off-Produkten beschränkt (Persistenz in der Umwelt).`},cyclotetrasiloxane:{note:`In der EU als fortpflanzungsgefährdend und persistent eingestuft; beschränkt.`},dimethicone:{note:`Inerter Filmbildner; sicher, kann sich jedoch auf dem Haar anreichern.`},amodimethicone:{note:`Pflegendes Silikon, gut verträglich.`},parfum:{note:`Nicht deklarierte Mischung – die häufigste Ursache für Kosmetikallergien.`},fragrance:{note:`Nicht deklarierte Mischung – die häufigste Ursache für Kosmetikallergien.`},limonene:{note:`Zitrus-Duftstoffkomponente; im oxidierten Zustand ein deklarationspflichtiges EU-Allergen.`},linalool:{note:`Blumige Duftstoffkomponente; im oxidierten Zustand ein deklarationspflichtiges EU-Allergen.`},citronellol:{note:`Deklarationspflichtiges EU-Duftstoffallergen.`},geraniol:{note:`Deklarationspflichtiges EU-Duftstoffallergen.`},eugenol:{note:`Deklarationspflichtiges EU-Duftstoffallergen.`},coumarin:{note:`Deklarationspflichtiges EU-Duftstoffallergen.`},"hexyl cinnamal":{note:`Deklarationspflichtiges EU-Duftstoffallergen.`},"benzyl salicylate":{note:`Deklarationspflichtiges EU-Duftstoffallergen.`},"alcohol denat":{note:`Trocknet die Haut in hoher Konzentration aus; weiter unten in der Liste unbedenklich.`},"propylene glycol":{note:`Feuchthaltemittel/Lösungsmittel; gelegentliche Empfindlichkeit.`},"peg-":{note:`Ethoxylierte Verbindung; Spuren von 1,4-Dioxan aus der Herstellung möglich.`},"p-phenylenediamine":{note:`Starkes Sensibilisierungsmittel – der Klassiker unter den Haarfärbeallergien; in der EU beschränkt.`},resorcinol:{note:`Haarfärbekomponente mit Hinweisen auf Schilddrüsenaktivität.`},hydroquinone:{note:`Hautaufhellendes Mittel, das in EU-Kosmetika verboten ist.`},toluene:{note:`Neurotoxisches Lösungsmittel; in EU-Kosmetika verboten.`},"salicylic acid":{note:`Peelendes BHA; EU-Konzentrationsgrenzwerte, bei Kleinkindern meiden.`},retinol:{note:`Wirksamer Anti-Aging-Wirkstoff; EU beschränkt die Konzentration, in der Schwangerschaft meiden.`},"aluminum chlorohydrate":{note:`Antitranspirant-Salz; SCCS stufte die derzeitigen Verwendungen als sicher ein (2020).`},talc:{note:`Sicher auf der Haut, wenn asbestfrei; einatembare Pulver von den Lungen fernhalten.`},"mineral oil":{note:`Okklesiv; Reinheit ist entscheidend (kosmetische Qualität ist raffiniert).`},"paraffinum liquidum":{note:`Mineralöl nach seinem INCI-Namen; raffinierte Qualitäten sind sicher.`},petrolatum:{note:`Okklusiv; sicher, wenn ordnungsgemäß raffiniert (die EU schreibt dies vor).`},lanolin:{note:`Aus Wolle gewonnen; wirksam, aber ein bekanntes Kontaktallergen.`},glycerin:{note:`Feuchthaltemittel, das Feuchtigkeit bindet; gehört zu den sichersten Inhaltsstoffen in Kosmetika.`},"hyaluronic acid":{note:`Feuchtigkeitsbindender Wirkstoff, sehr gut verträglich.`},"sodium hyaluronate":{note:`Salzform der Hyaluronsäure; gut verträglich.`},panthenol:{note:`Provitamin B5 – wirklich pflegend und risikoarm.`},niacinamide:{note:`Vitamin B3 – wissenschaftlich belegt und gut verträglich.`},tocopherol:{note:`Vitamin-E-Antioxidationsmittel.`},ceramide:{note:`Hautidentische Lipide; Unterstützung der Hautbarriere.`}},r={ui:e,additives:t,inci:n};export{t as additives,r as default,n as inci,e as ui};